INSERT INTO `tbl_content_pages_block_lang` VALUES (1,1,1,1,'\r\n<div class=\"content-wrap\">                \r\n	<div class=\"content-block content-block-even\">                    \r\n		<div class=\"content-block-img\">                        <img src=\"../images/about-left-pic.png\" alt=\"\" />                    </div>                    \r\n		<div class=\"content-block-cms\">                        \r\n			<div class=\"cms cms-about-us\">                            \r\n				<h2>Who We Are</h2>                            \r\n				<p>There are many variations of passages of Lorem Ipsum available, but the majority have suffered alteration in some form, by injected humour, or randomised words which don\'t look even slightly believable. If you are going to use a passage of Lorem Ipsum, you need to be sure there isn\'t anything embarrassing hidden in the middle of text.</p>     \r\n          \r\n				<ul>\r\n					<li>Lorem ipsum dolor sit amet, consectetur adipiscing elit.</li>\r\n					<li>Proin dictum tortor et ex mollis dignissim.</li>\r\n					<li>Nullam commodo lorem vitae tortor consectetur, in suscipit nisi dignissim.</li>\r\n					<li>Etiam at nunc vel ipsum vestibulum vehicula.</li>\r\n					<li>Vestibulum condimentum metus ut feugiat euismod.</li>\r\n				</ul></div>                    </div>                </div>            </div> '),(2,1,1,2,'\r\n<div class=\"bg-stats\">                \r\n	<div class=\"section-head section-head-center\">                    \r\n		<div class=\"section-heading\">                        \r\n			<h2>We have impactful results</h2>                    </div>                </div>                \r\n	<div class=\"stats\">                    \r\n		<div class=\"stats-block\">                        \r\n			<h4>99%</h4>                        \r\n			<p>Customer satisfaction</p>                    </div>                    \r\n		<div class=\"stats-block\">                        \r\n			<h4>32M</h4>                        \r\n			<p>Original Artwo