INSERT INTO `tbl_email_templates` VALUES ('abandoned_cart_deleted_discount_notification',1,'Abandoned Cart Deleted Discount Notification','Abandoned Cart Deleted Discount Notification','\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody> \r\n						<tr>\r\n							<td style=\"text-align: center; padding-top: 60px\"><img src=\"./email-logo.png\" alt=\"\" /></td>\r\n						</tr>\r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong></td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:0 10px; line-height:1.3; text-align:center; color:#333333;vertical-align:top; font-size: 30px;\">We noticed you removed <span style=\"text-decoration: underline;\">{product_name}</span> from your cart.</td>                                    \r\n						</tr> \r\n														   \r\n						<tr>                                    \r\n							<td style=\"padding:20px 0 10px 10px; line-height:1.3; text-align:center; color:#999999;vertical-align:top; font-size:16px;\">Just for you : Get <span style=\"color:#333; font-weight: bold;\">{discount}</span> off on your order with code <span style=\"color:#333; font-weight: bold;\">{coupon_code}.</span>                                                   <a href=\"{checkout_now}\" style=\"background: #ff3a59;border:none; border-radius: 4px; color: #fff; cursor: pointer;margin:10px 0 0 0;width: auto; font-weight: normal; padding: 10px 20px; display: inline-block; \">Check out now </a></td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table>    </td>\r\n		</tr>\r\n	</tbody>\r\n</table>','{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n{discount} <br>\r\n{coupon_code} <br>\r\n{checkout_now} <br>',5,1),('abandoned_cart_discount_notification',1,'Abandoned Cart Discount Notification','Abandoned Cart Discount Notification','\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Abandoned Cart Discount</h2></td>                    \r\n		</tr>  \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong></td>                                    \r\n						</tr>                                    \r\n						<tr>                                                \r\n							<td style=\"padding:0 10px; line-height:1.3; text-align:center; color:#333333;vertical-align:top; font-size: 30px;\">Finish your order before your items sell out!</td>                                    \r\n						</tr> \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 10px 10px; line-height:1.3; text-align:center; color:#999999;vertical-align:top; font-size:16px;\">Just for you : Get <span style=\"color:#333; font-weight: bold;\">{discount} OFF</span> off on your order with code <span style=\"color:#333; font-weight: bold;\">{coupon_code}.</span>                                        <a href=\"{checkout_now}\" style=\"background: #ff3a59;border:none; border-radius: 4px; color: #fff; cursor: pointer;margin:10px 0 0 0;width: auto; font-weight: normal; padding: 10px 20px; display: inline-block;\">Check out now </a></td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:30px 0;\">                                            \r\n								<table>                                                \r\n									<tbody>\r\n										<tr>                                                    \r\n											<td style=\"padding-right: 25px;\"><img style=\"border: solid 1px #ececec; padding: 10px; border-radius: 4px;\" src=\"{product_image}\" /></td>                                                    \r\n											<td style=\"text-align: left;\">                                                        <span style=\"font-size: 20px; font-weight:normal; color:#999999; \">{product_name}</span>                                                         <span style=\"font-size: 14px; font-weight: bold; color:#000000; display: block; padding: 20px 0;\">{product_price}</span>                                                    </td>                                                \r\n										</tr>                                            \r\n									</tbody>\r\n								</table></td>                              