INSERT INTO `tbl_extra_pages` VALUES (16,'Seller\'s Registration Page (Block 3)',16,0,1,0,'<div class=\"row\">\r\n	<div class=\"col-lg-6 col-md-6 col-sm-12 col-xs-12\">      \r\n		<div class=\"growth\" style=\"background-image:url(/images/customer.png);\"><strong>5+</strong><br />\r\n			 Millions Customers</div>      \r\n		<div class=\"growth\" style=\"background-image:url(/images/bussiness.png);\"><strong>1000+</strong><br />\r\n			 Business Growing rapidly with us</div>  </div>\r\n	<div class=\"col-lg-6 col-md-6 col-sm-12 col-xs-12\">\r\n		<ul class=\"growth-txt\">          \r\n			<li><i class=\"icn\"><img src=\"/images/star-unique.png\" alt=\"\" /></i> \r\n				<h4>Consectetur \r\n					adipisicing</h4>\r\n				<p>Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do 					 incididunt ut labore et dolore magna aliqua.</p>  </li>          \r\n			<li><i class=\"icn\"><img src=\"/images/folder.png\" alt=\"\" /></i> \r\n				<h4>Consectetur \r\n					adipisicing</h4>\r\n				<p>Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do 					 incididunt ut labore et dolore magna aliqua.</p>  </li>\r\n		</ul>  </div></div>','null','2022-09-04 17:42:36'),(17,'Seller\'s Registration Page (Block 4)',17,0,1,0,'     <div class=\"section-head section-head-center\">                        \r\n	<div class=\"section-heading\">                            \r\n		 \r\n		<h2>Simple steps to start selling online</h2>                  </div>                    </div>        \r\n<div class=\"seller-steps\">  \r\n	<ul>      \r\n		<li><i class=\"icn\"><img src=\"/images/easyto-use.png\" alt=\"\" /></i>  \r\n			<h3></h3>\r\n			<h3>Easy to Use</h3>  \r\n			<p>Set up simulation exercises for large group of students in a few steps.</p></li>      \r\n		<li><i class=\"icn\"><img src=\"/images/real-market.png\" alt=\"\" /></i>  \r\n			<h3>Real Market Data</h3>  \r\n			<p>Use real financial markets data in simulation activities.</p></li>      \r\n		<li><i class=\"icn\"><img src=\"/images/simulated.png\" alt=\"\" /></i>  \r\n			<h3>Simulated Market Data</h3>  \r\n			<p>Simulate past market events and data over a specific historical time period.</p></li>      \r\n		<li><i class=\"icn\"><img src=\"/images/customization.png\" alt=\"\" /></i>  \r\n			<h3>Fully Customisable</h3>  \r\n			<p>Fully customize activities to meet various learning outcomes, disciplines and levels of difficulty.</p></li>  \r\n	</ul></div>','null','2022-09-04 17:42:53'),(18,'Selling on Yo!Kart is Easy!',18,0,1,0,'<h3>Selling on YoKart is easy! <span class=\"\">All you need is:</span> </h3> <ul>   	<li><i class=\"fa fa-check\" aria-hidden=\"true\"></i> VAT Number </li>   	<li><i class=\"fa fa-check\" aria-hidden=\"true\"></i> PAN Card </li>   	<li><i class=\"fa fa-check\" aria-hidden=\"true\"></i> Current Account Number </li> </ul>','{\"1\":\"no-repeat\",\"2\":\"cover\"}','2022-10-19 14:37:42'),(20,'Seller side Subscription Package module',20,0,1,0,'<h3>Simple Pricing With No Surprises</h3>           <p>Subscription plans and At vero eos et accusamus et iusto odio dignissimos<br /> 	            ducimus qui blanditiis quas molestias excepturi sint occaecati cupiditate non provident. </p>','null','2022-09-04 17:32:38'),(21,'Advertiser with us',21,0,1,0,'<h3>Make Money <span class=\"\">by becoming a Yo!kart Affiliate!</span></h3> <p>Our affiliate program is easy & free to join! It enables you to earn revenue by referring potential customers to our website. Whether you are a large content network, social media butterfly or a seasoned blogger, you can earn our standard 5.00% commission on referred purchases. For more information, please visit our FAQ page and don’t forget to read our Terms & Conditions.</p>','{\"1\":\"no-repeat\",\"2\":\"cover\"}','2022-08-18 18:38:30'),(22,'Affiliate program to make money',22,0,1,0,'<h3>Make Money <span class=\"\">by becoming a Yo!kart Affiliate!</span></h3> <p>Our affiliate program is easy & free to join! It enables you to earn revenue by referring potential customers to our website. Whether you are a large content network, social media butterfly or a seasoned blogger, you can earn our standard 5.00% commission on referred purchases. For more information, please visit our FAQ page and don’t forget to read our Terms & Conditions.</p>','{\"1\":\"no-repeat\",\"2\":\"cover\"}','2022-08-26 15:52:23'),(24,'Seller\'s Registration Page (Block 2)',24,0,1,0,'<p>Need Help In Getting Pan/vat?<br />\r\n	<a href=\"\" class=\"\">Click Here</a> To Contact Our Partners Near Your Location</p>','null','2022-10-19 14:51:08'),(25,'Seller\'s Registration Page (Block 5)',25,0,1,0,'  <div class=\"section-head section-head-center\">                        \r\n	<div class=\"section-heading\">                            \r\n		<h2>Simple Pricing Structure</h2>                        </div>                    </div>\r\n<div class=\"pricing-structure\">  \r\n	<ul>\r\n		<li>10%  \r\n			<p>Commission Fee</p></li>\r\n		<li class=\"sign\">+</li>\r\n		<li>$1  \r\n			<p>Shipping Fee</p></li>\r\n		<li class=\"sign\">+</li>\r\n		<li>$4   \r\n			<p>Marketplace Fee</p></li>\r\n		<li class=\"sign\">+</li>\r\n		<li>15%   \r\n			<p>Service Tax</p></li>\r\n		<li class=\"sign\">+</li>\r\n		<li>Amt.   \r\n			<p>Amount You Earned</p></li>\r\n		<li class=\"sign\">=</li>\r\n		<li>Price   \r\n			<p>Price You Decide</p></li>  \r\n	</ul></div>\r\n<div class=\"align-center\">  \r\n	<p>Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum voluptatem.</p><a href=\"#\" class=\"btn btn-outline-brand mt-4\">Learn More About Pricing</a></div>','null','2022-09-04 17:43:16'),(26,'Footer Trust Banners (Only on Homepage)',26,0,1,0,'<div class=\"container\">\r\n            <div class=\"incentives-layout-1\">\r\n                <div class=\"incentives\">\r\n                    <div class=\"incentives-icon\">\r\n                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\">\r\n                    </div>\r\n                    <h3 class=\"incentives-title\">100% PAYMENT SECURE</h3>\r\n                    <p class=\"incentives-text\">We ensure secure payment with PEV</p>\r\n                </div>\r\n                <div class=\"incentives\">\r\n                    <div class=\"incentives-icon\">\r\n                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\">\r\n                    </div>\r\n                    <h3 class=\"incentives-title\">FREE SHIPPING</h3>\r\n                    <p class=\"incentives-text\">Free shipping on all US order or order above $200 </p>\r\n                </div>\r\n                <div class=\"incentives\">\r\n                    <div class=\"incentives-icon\">\r\n                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\">\r\n                    </div>\r\n                    <h3 class=\"incentives-title\">30 DAYS RETURN</h3>\r\n                    <p class=\"incentives-text\">Simply return it within 30 days for an exchange.</p>\r\n                </div>\r\n                <div class=\"incentives\">\r\n                    <div class=\"incentives-icon\">\r\n                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\">\r\n                    </div>\r\n                    <h3 class=\"incentives-title\">100% PAYMENT SECURE</h3>\r\n                    <p class=\"incentives-text\">We ensure secure payment with PEV</p>\r\n                </div>\r\n\r\n            </div>            \r\n        </div>','null','2022-09-04 15:38:08'),(28,'Admin Product Categories',28,1,1,0,'<div>&nbsp;</div> <div> 	<h1>Categories Content File</h1><br /> 	</div> <h3>Category Identifier</h3> <div>User defined free text field for unique identifier of the category. This works as a unique key for the system to identify a particular category.</div> <div><br /> 	</div> <h3>Parent Identifier</h3> <div>Parent Identifier is used for categories that belong to a root/master category, essentially they are subcategories to root categories. For a category that is root/master category the parent identifier needs to be left blank.</div> <div><br /> 	</div> <div>  </div> <h3>Name</h3> <div>User defined name for the category.</div> <div><br /> 	</div> <div>&nbsp;</div> <h3>Description</h3> <div>User defined description for the category.</div> <div><br /> 	</div> <div>&nbsp;</div> <h3>SEO Friendly URL</h3> <div>User defined URL for the category for SEO purposes. Spaces cannot be used in the URL.</div> <div><br /> 	</div> <div> </div> <h3>Featured</h3> <div>User defined field to mark a particular category as featured or not. Possible inputs for this field are ‘Yes’ &amp; ‘No’.</div> <div>&nbsp;</div> <div> </div> <h3>Active</h3> <div>User defined field to mark a particular category as active in the system or not. Possible inputs for this field are ‘Yes’ &amp; ‘No’. Default value should be set as ’Yes’.</div> <div>&nbsp;</div> <div> </div> <h3>Display Order</h3>User defined field to set priority on display order of root categories or sub-categories within a root category. If more than one category has display order set to the same value then the system will display category that was added first. If you are unsure about this field add display order as ‘1’ to all the categories.     <h3>&nbsp;</h3> <h3>Deleted</h3>User defined field to mark a particular category as deleted in the system or not. Possible inputs for this field are ‘Yes’ &amp; ‘No’. Default value should be set as ’No’ to display categories in the system.  <h1>&nbsp;</h1> <h1>Categories Media File</h1> <h3>&nbsp;</h3> <h3>Category Identifier</h3>User defined unique identifier for the category. This field needs to be the same as Category Identifier defined in Categories Content sheet.    <h3>&nbsp;</h3> <h3>Lang Code</h3>User defined field to link the category image for a particular language. ‘Universal’ is to be used as an option to link the media in all languages. Language codes can be looked up by clicking the language option in the top header. Language codes need to be used if the Category has different images for each language.  <h3>&nbsp;</h3> <h3>Image Type</h3>User defined field with input options of ‘Category Icon’ &amp; ‘Category Banner’. Category icon option is to be used when uploading icon image for the category. Category banner option is to be used when uploading banner image for the category page.    <h3>&nbsp;</h3> <h3>File Path</h3>File path needs to be a publically accessible URL for example URL’s from Google Drive, Dropbox etc. Images stored locally on your personal device/machine cannot be uploaded. Preferred image dimensions for Category Icon are 60*60 pixels. Preferred image dimensions for Category banner are 1050*340 pixels.  <h3>&nbsp;</h3> <h3>File Name</h3>Name of the image file  <h3>&nbsp;</h3> <h3>Display order</h3>When a category has multiple images then this field defines the order of display. If you are unsure about this field add display order as ‘1’ to all the categories.','','2022-09-09 11:09:29'),(30,'Admin Brands',30,1,1,0,'<h2>&nbsp;</h2> <h2>Brands Content File</h2> <h3>&nbsp;</h3> <h3>Brand Identifier</h3>User defined unique identifier for the Brand. This works as a unique key for the system to identify a particular Brand. <h3>&nbsp;</h3> <h3>Name</h3>User defined name for the Brand in the system.  <h3>&nbsp;</h3> <h3>Description</h3>User defined description for the Brand. <h3>&nbsp;</h3> <h3>SEO Friendly URL</h3> User defined URL for the Brand for SEO purposes. Spaces cannot be used in the URL.  <h3>&nbsp;</h3> <h3>Featured</h3>User defined field to mark a particular Brand as featured or not. Possible inputs for this field are \'Yes\' &amp; \'No\'.  <h3>&nbsp;</h3> <h3>Active</h3>User defined field to mark a particular category as active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\'.  <h2>&nbsp;</h2> <h2>Brands Media File</h2> <h3>&nbsp;</h3> <h3>Brand Identifier</h3>User defined unique identifier for the Brand. This field needs to be the same as Brand Identifier defined in Brands Content sheet.    <h3>&nbsp;</h3> <h3>Lang Code</h3>User defined field to link the brand image for a particular language. \'Universal\' is to be used as an option to link the media in all languages. Language codes can be looked up by clicking the language option in the top header. Language codes need to be used if the Brand has different images for each language.  <h3>&nbsp;</h3> <h3>File Path</h3>File path needs to be a publicly accessible URL for example URL\'s from Google Drive, Dropbox etc. Images stored locally on your personal device/machine cannot be uploaded. Preferred image dimensions are 192*82 pixels. <h3>&nbsp;</h3> <h3>File Name</h3>Name of the image file  <h3>&nbsp;</h3> <h3>Display order</h3>When a brand has multiple images then this field defines the order of display. If you are unsure about this field add display order as \'1\' to all the brands.','','2022-09-08 15:59:05'),(31,'Admin Options',31,1,1,0,'<h2><br /> 	<br /> 	Options Content File</h2> <h3>&nbsp;</h3> <h3>Option Identifier</h3>User defined unique identifier for the Option. This works as a unique key for the system to identify a particular Option. <h3>&nbsp;</h3> <h3>Option Name</h3>User defined name for the Option. <h3>&nbsp;</h3> <h3>Username</h3>For admin this field needs to be left blank. In case an option is added by a seller then seller username will be displayed in this field.   <h3>&nbsp;</h3> <h3>Is separate image</h3>User defined input field to denote if the option would have a separate image. Useful for color options of the product. Possible inputs for this field are \'Yes\' &amp; \'No\'.     <h3>&nbsp;</h3> <h3>Is color type</h3>User defined input field to denote if option is a color. Possible inputs for this field are \'Yes\' &amp; \'No\'. <h3>&nbsp;</h3> <h3>Display in filters</h3>User defined input field to denote if option is to be displayed in the filters on the product listing page. Possible inputs for this field are \'Yes\' &amp; \'No\'. <h3>&nbsp;</h3> <h3>Deleted</h3>User defined field to mark a particular option as deleted in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'No\' to display categories in the system. <h2>&nbsp;</h2> <h2>Options Values File</h2> <h3>&nbsp;</h3> <h3>Option value identifier</h3>User defined unique identifier for the Option value. This works as a unique key for the system to identify a particular Option value. <h3>&nbsp;</h3> <h3>Option Identifier</h3>User defined unique identifier for the option. This field value needs to be the same as the Option Identifier defined in Options Content sheet.    <h3>&nbsp;</h3> <h3>Option Value</h3>User defined value for the Option.  <h3>&nbsp;</h3> <h3>Color code</h3>User defined Hexadecimal value for the color of the option. Only to be used if the option is a color. Leave this field blank if the option is not a color. Hexadecimal for a color can be searched on Google.   <h3>&nbsp;</h3> <h3>Display order</h3>When an option has multiple option values then this field defines the order of display of the option value. If you are unsure about this field add display order as \'1\'.','','2022-09-09 10:54:35'),(32,'Admin Tags',32,1,1,0,'<h2><br /> 	<br /> 	Tags Content File</h2> <h3><br /> 	<br /> 	Tag Identifier</h3>User defined unique identifier for the Tag. This works as a unique key for the system to identify a particular Tag. <h3><br /> 	<br /> 	Username</h3>For admin this field needs to be left blank. In case a tag is added by a seller then seller username will be displayed in this field.   <h3><br /> 	<br /> 	Tag name</h3>User defined name for the Tag.','','2022-09-09 11:12:38'),(33,'Admin Countries Management',33,1,1,0,'<br />  <h2>Countries Content File </h2>  <h3><br /> 	<br /> 	Country Code</h3>User defined field for unique country code.  <h3><br /> 	<br /> 	Country Name</h3>User defined field for unique country name.  <h3><br /> 	<br /> 	Currency Code</h3>User defined field for unique currency code for the country.  <h3><br /> 	<br /> 	Language Code</h3>Language code for the country can be input here. \'Universal\' is to be used as an option if there is no preference, else relevant language code needs to be associated with the country. For example we will use \'ENG\' for the United States.   <h3><br /> 	<br /> 	Active</h3>User defined field to mark a particular country as active in the system or not. Possible inputs for this field are \'Yes\' & \'No\'. Default value should be set as \'Yes\'.','','2022-09-09 10:51:47'),(34,'Admin State Management',34,1,1,0,'<br />  <h2>States Content File</h2>  <h3><br /> 	<br /> 	State Identifier</h3>User defined unique identifier for the State. This works as a unique key for the system to identify a particular State. <h3><br /> 	<br /> 	Country Code</h3>This field needs to be the same as country code defined in Countries Content sheet.    <h3><br /> 	<br /> 	Sate Name</h3>User defined field for unique state name. <h3><br /> 	<br /> 	State Code</h3>User defined field for unique state code. <h3><br /> 	<br /> 	Active</h3>User defined field to mark a particular state as active in the system or not. Possible inputs for this field are \'Yes\' & \'No\'. Default value should be set as \'Yes\'.','','2022-09-09 11:11:17'),(35,'Admin Manage Catalog',35,1,1,0,'<div class=\"grouplisting\">                             	<div class=\"groups group-js\">                                 		<div class=\"group__head group__head-js\"> 			<h5> Product Catalog Content </h5></div>                                 		<div class=\"group__body group__body-js\">                                     			<h5>Product Identifier</h5>                                     			<p>User defined unique identifier for the Product. This works as a unique key for the system to identify a particular Product.</p>                                     			<h5>Username</h5>                                     			<p>For admin this field needs to be left blank. In case an option is added by a seller then seller username will be displayed in this field.  </p>                                     			<h5>Name</h5>                                     			<p>User defined field for product name.</p>                                     			<h5>Description</h5>                                     			<p>User defined field for product description. </p>                                     			<h5>Youtube video</h5>                                     			<p>User defined field for product Youtube video URL</p>                                     			<h5>Category Identifier</h5>                                     			<p> User defined unique identifier for the category. This field needs to be the same as Category Identifier defined in Categories Content sheet.  </p>                                     			<h5>Brand Identifier</h5>                                     			<p>User defined unique identifier for the Brand. This field needs to be the same as Brand Identifier defined in Brand Content sheet.  </p>                                     			<h5>Product Type Identifier</h5>                                     			<p>User defined input field to denote the type of the Product. Possible inputs for this field are \'Physical\' &amp; \'Digital\'. </p>                                     			<h5>Model</h5>                                     			<p>User defined field for product model.</p>                                     			<h5>Minimum selling price</h5>                                     			<p>User defined field for minimum selling price for the product.</p>                                     			<h5>Tax Category Identifier</h5>                                     			<p>User defined unique identifier for the Tax category. This field needs to be the same as Tax Category Identifier defined in the Admin console under the Sales Tax option page.</p>                                     			<h5>Length</h5>                                     			<p>User defined field for product package length.</p>                                     			<h5>Width</h5>                                     			<p>User defined field for product package width.</p>                                                                          			<h5>Height</h5>                                     			<p>User defined field for product package Height.</p>                                                                          			<h5>Dimension Unit Identifier</h5>                                     			<p>User defined input field to denote the unit of the dimensions of the package. Possible inputs for this field are \'Inch\', \'Centimeter\' &amp; \'Feet\'. </p>                                                                          			<h5>Weight </h5>                                     			<p>User defined field for product package Weight.</p>                                     			<h5>Weight Unit Identifier</h5>                                     			<p>User defined input field to denote the unit of the weight of the package. . Possible inputs for this field are \'Gram\', \'Kilogram\' &amp; \'Pound\'.</p>                                     			<h5>Ean/upc Code</h5>                                     			<p>User defined field for EAN/UPC code of the product.</p>                                     			<h5>Shipping country Code</h5>                                     			<p>This field needs to be the same as country code defined in Countries Content sheet.  </p>                                     			<h5>Added On</h5>                                     			<p>User defined field for product add date to the system.</p>                                     			<h5>Free Shipping</h5>                                     			<p>User defined field to mark a particular Product is available for free shipping. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>                                     			<h5>COD Available</h5>                                     			<p>User defined field to mark a particular Product is available for Cash on Delivery or not. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>                                     			<h5>Featured</h5>                                     			<p>User defined field to mark a particular Product as featured or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. </p>                                     			<h5>Approved</h5>                                     			<p>User defined field to mark a particular Product as Approved or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\' to display products in the system.</p>                                     			<h5>Active</h5>                                     			<p>User defined field to mark a particular Product as active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\'. </p>                                     			<h5>Deleted</h5>                                     			<p>User defined field to mark a particular product as deleted in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'No\' to display products in the system. </p>                                </div>                            </div>                             	<div class=\"groups group-js\">                                 		<div class=\"group__head group__head-js\"> 			<h5> Product Option Content </h5></div>                                 		<div class=\"group__body group__body-js\">                                     			<ul>                                                                              				<li>                                                                                      					<h5>Product Identifier</h5>                                                                                      					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet. </p>                                    </li>                                                                              				<li>                                                                                      					<h5>Option Identifier</h5>                                                                                      					<p>User defined unique identifier for the Option. This field needs to be the same as Option Identifier defined in Option Content sheet. </p>                                        </li>                                                                      			</ul>                                </div>                            </div>                             	<div class=\"groups group-js\">                                 		<div class=\"group__head group__head-js\"> 			<h5> Product Tag Content</h5></div>                                 		<div class=\"group__body group__body-js\">                                     			<ul>                                                                              				<li>                                                                                      					<h5>Product Identifier</h5>                                                                                      					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet.</p>                                    </li>                                                                              				<li>                                                                                      					<h5>Tag Identifier</h5>                                                                                      					<p>User defined unique identifier for the Tag. This field needs to be the same as Tag Identifier defined in Tag Content sheet. </p>                                    </li>                                                                      			</ul>                                </div>                            </div>                             	<div class=\"groups group-js\">                                 		<div class=\"group__head group__head-js\"> 			<h5> Product Specification Content </h5></div>                                 		<div class=\"group__body group__body-js\">                                     			<ul>                                                                              				<li>                                                                                      					<h5>Product Identifier</h5>                                                                                      					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet.    </p>                                    </li>                                                                              				<li>                                                                                      					<h5>Lang Code</h5>                                                                                      					<p>User defined field to link the product specification for a particular language. Language codes can be looked up by clicking the language option in the top header. </p>                                    </li>                                                                              				<li>                                                                                      					<h5>Specification Name</h5>                                                                                      					<p>User defined field for product specification name.</p>                                    </li>                                                                              				<li>                                                                                      					<h5>Specification Value</h5>                                                                                      					<p>User defined field for product specification Value.</p>                                    </li>                                                                      			</ul>                                </div>                            </div>                             	<div class=\"groups group-js\">                                 		<div class=\"group__head group__head-js\"> 			<h5> Product Shipping Content </h5></div>                                 		<div class=\"group__body group__body-js\">                                     			<ul>                                                                          				<li>                                                                                  					<h5>Product Identifier</h5>                                                                                  					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet.</p>                                    </li>                                                                          				<li>                                                                                  					<h5>Username</h5>                                                                                  					<p>For admin this field needs to be left blank. In case an option is added by a seller then seller username will be displayed in this field. </p>                                    </li>                                                                          				<li>                                                                                  					<h5>Shipping Country Code</h5>                                                                                  					<p>This field needs to be the same as country code defined in Countries Content sheet. This field can be left blank if the product has no restrictions on the countries it is shipped to.</p>                                    </li>                                                                          				<li>                                                                                  					<h5>Shipping Company Identifier</h5>                                                                                  					<p>User defined unique identifier for the Shipping company identifier. This field needs to be the same as the Shipping Company Identifier defined in the Admin console>Shipping API>Shipping Companies page.  </p>                                        </li>                                                                          				<li>                                                                                  					<h5>Shipping Duration Identifier</h5>                                                                                  					<p>User defined unique identifier for the Shipping Duration identifier. This field needs to be the same as the Shipping Duration Identifier defined in the Admin console>Shipping API>Duration Labels page. </p>                                    </li>                                                                          				<li>                                                                                  					<h5>Cost</h5>                                                                                  					<p>User defined field for product shipping cost.</p>                                    </li>                                                                          				<li>                                                                                  					<h5>Additional Item Cost</h5>                                                                                  					<p>User defined field for additional shipping cost per product.</p>                                    </li>                                                                  			</ul>                                </div>                            </div>                             	<div class=\"groups group-js\">                                 		<div class=\"group__head group__head-js\"> 			<h5> Product Catalog Media  </h5></div>                                 		<div class=\"group__body group__body-js\">                                     			<ul>                                                                          				<li>                                                                                  					<h5>Product Identifier</h5>                                                                                  					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet. </p>                                    </li>                                                                          				<li>                                                                                  					<h5>Lang Code</h5>                                                                                  					<p>User defined field to link the product image for a particular language. \'Universal\' is to be used as an option to link the media in all languages. Language codes can be looked up by clicking the language option in the top header. Language codes need to be used if the Product has different images for each language.</p>                                    </li>                                                                          				<li>                                                                                  					<h5>Option Identifier</h5>                                                                                  					<p>User defined unique identifier for the option. This field value needs to be the same as the Option Identifier defined in Options Content sheet.   </p>                                    </li>                                                                          				<li>                                                                                  					<h5>Option value Identifier</h5>                                                                                  					<p>User defined unique identifier for the option value. This field value needs to be the same as the Option value Identifier defined in Options Value Content sheet. </p>                                    </li>                                                                          				<li>                                                                                  					<h5>File Path</h5>                                                                                  					<p>File path needs to be a publically accessible URL for example URL\'s from Google Drive, Dropbox etc. Images stored locally on your personal device/machine cannot be uploaded. Preferred image dimensions for the product images are greater than 500*500 pixels. </p>                                    </li>                                                                          				<li>                                                                                  					<h5>File Name</h5>                                                                                  					<p>Name of the image file. </p>                                    </li>                                                                          				<li>                                                                                  					<h5>Display order</h5>                                                                                  					<p>When a product has multiple images then this field defines the order of display. If you are unsure about this field add display order as \'1\'. </p>                                    </li>                                                                  			</ul>                                </div>                            </div>                        </div>','','0000-00-00 00:00:00'),(36,'Seller Manage Catalog',36,1,1,0,'<div class=\"grouplisting\">                             	<div class=\"groups group-js\">                                 		<div class=\"group__head group__head-js\"> 			<h5> Seller Catalog – Product Catalog </h5></div>                                 		<div class=\"group__body group__body-js\">                                     			<ul>                                                                      				<li>                                                                                      					<h5>Product Identifier </h5>                                                                                      					<p>User defined unique identifier for the Product. This works as a unique key for the system to identify a particular Product.</p>                                        </li>                                         				<li>                                                                                      					<h5>Username </h5>                                                                                      					<p>For admin this field needs to be left blank. In case a product is added by a seller then seller username will be displayed in this field.  </p>                                        </li>                                            				<li>                                                                                      					<h5>Name </h5>                                                                                      					<p>User defined field for product name.</p>                                        </li>                                            				<li>                                                                                      					<h5>Description </h5>                                                                                      					<p>User defined field for product description. er</p>                                        </li>                                            				<li>                                                                                      					<h5>Youtube video</h5>                                                                                      					<p>User defined field for product Youtube video URL. </p>                                        </li>                                            				<li>                                                                                      					<h5>Category Identifier</h5>                                                                                      					<p>User defined unique identifier for the category. This field needs to be the same as the Category Identifier defined in Categories export sheet.   </p>                                        </li>                                            				<li>                                                                                      					<h5>Brand Identifier</h5>                                                                                      					<p>User defined unique identifier for the Brand. This field needs to be the same as Brand Identifier defined in Brand  sheet.   </p>                                        </li>                                            				<li>                                                                                      					<h5>Product Type Identifier</h5>                                                                                      					<p>User defined input field to denote the type of the Product. Possible inputs for this field are \'Physical\' &amp; \'Digital\'. </p>                                        </li>                                            				<li>                                                                                      					<h5>Model </h5>                                                                                      					<p>User defined field for product model.</p>                                        </li>                                            				<li>                                                                                      					<h5>Minimum selling price</h5>                                                                                      					<p>User defined field for minimum selling price for the product.</p>                                        </li>                                            				<li>                                                                                      					<h5>Tax Category Identifier</h5>                                                                                      					<p>User defined unique identifier for the Tax category. This field needs to be the same as Tax Category Identifier defined in tax category export sheet.   </p>                                        </li>                                            				<li>                                                                                      					<h5>Length</h5>                                                                                      					<p>User defined field for product package length.</p>                                        </li>                                            				<li>                                                                                      					<h5>Width</h5>                                                                                      					<p>User defined field for product package width.</p>                                        </li>                                            				<li>                                                                                      					<h5>Height</h5>                                                                                      					<p>User defined field for product package Height.</p>                                        </li>                                            				<li>                                                                                      					<h5>Dimension Unit Identifier </h5>                                                                                      					<p> User defined input field to denote the unit of the dimensions of the package. Possible inputs for this field are \'Inch\', \'Centimeter\' &amp; \'Feet\'.    </p>                                        </li>                                            				<li>                                                                                      					<h5>Weight </h5>                                                                                      					<p>User defined field for product package Weight.</p>                                        </li>                                                                                     				<li>                                                                                      					<h5>Weight Unit Identifier</h5>                                                                                      					<p>User defined input field to denote the unit of the weight of the package. . Possible inputs for this field are \'Gram\', \'Kilogram\' &amp; \'Pound\'. </p>                                        </li>                                            				<li>                                                                                      					<h5>Ean/upc Code</h5>                                                                               