INSERT INTO `tbl_extra_pages_lang` VALUES (0,1,'Seller Badges Instructions','<div class=\"alert alert-info\" role=\"alert\"><div class=\"alert-text\">Badges can be added by admin only.</div></div>'),(16,1,'Seller\'s Registration Page (Block 3)','\r\n<div class=\"container\">\r\n	<div class=\"section-head section-head-center\">                \r\n		<div class=\"section-heading\">                    \r\n			<h2>Become a Seller on Yokart in 3 easy steps</h2>                </div>            </div>            \r\n	<div class=\"easy-methods\">                \r\n		<div class=\"method\">                    \r\n			<div class=\"icon\">                        <img width=\"78.765\" height=\"73.283\" src=\"./images/retina/create-account.svg\" alt=\"\" />                    </div>                    \r\n			<div class=\"detail\">                        \r\n				<h3>Create Account</h3>                        \r\n				<p>Add your name and phone number to get started selling on Yokart.</p>                    </div>                </div>                \r\n		<div class=\"method\">                    \r\n			<div class=\"icon\">                        <img width=\"80\" height=\"80\" src=\"./images/retina/add-business.svg\" alt=\"\" />                    </div>                    \r\n			<div class=\"detail\">                        \r\n				<h3>Add Business</h3>                        \r\n				<p>Add name, address &amp; e-mail of your company, store/ business.</p>                    </div>                </div>                \r\n		<div class=\"method\">                    \r\n			<div class=\"icon\">                        <img width=\"80\" height=\"80\" src=\"./images/retina/add-products-services.svg\" alt=\"\" />                    </div>                    \r\n			<div class=\"detail\">                        \r\n				<h3>Add Products/ Services</h3>                        \r\n				<p>Minimum 3 products/ services needed for your free listing page.</p>                    </div>                </div>            </div></div>  '),(16,2,'Seller Page Block 2','<div class=\"row\">\r\n	<div class=\"col-lg-6 col-md-6 col-sm-12 col-xs-12\">      \r\n		<div class=\"growth\" style=\"background-image:url(/images/customer.png);\"><strong>5+</strong><br />\r\n			 Millions Customers</div>      \r\n		<div class=\"growth\" style=\"background-image:url(/images/bussiness.png);\"><strong>1000+</strong><br />\r\n			 Business Growing rapidly with us</div>  </div>\r\n	<div class=\"col-lg-6 col-md-6 col-sm-12 col-xs-12\">\r\n		<ul class=\"growth-txt\">          \r\n			<li><i class=\"icn\"><img src=\"/images/star-unique.png\" alt=\"\" /></i> \r\n				<h4>Consectetur \r\n					adipisicing</h4>\r\n				<p>Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do 					 incididunt ut labore et dolore magna aliqua.</p>  </li>          \r\n			<li><i class=\"icn\"><img src=\"/images/folder.png\" alt=\"\" /></i> \r\n				<h4>Consectetur \r\n					adipisicing</h4>\r\n				<p>Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do 					 incididunt ut labore et dolore magna aliqua.</p>  </li>\r\n		</ul>  </div></div>'),(17,1,'Seller\'s Registration Page (Block 4)','\r\n<div class=\"container\"> \r\n	<div class=\"container\">            \r\n		<div class=\"section-head section-head-center\">                \r\n			<div class=\"section-heading\">                    \r\n				<h2>Simple Pricing Structure</h2>                </div>            </div>            \r\n		<div class=\"pricing-structure\">                \r\n			<ul>                    \r\n				<li class=\"box\">                        \r\n					<h4>10%</h4>                        \r\n					<p>Commission Fee</p>                    </li>                    \r\n				<li class=\"sign\">+</li>                    \r\n				<li class=\"box\">                        \r\n					<h4>$1 </h4>                        \r\n					<p>Shipping Fee</p>                    </li>                    \r\n				<li class=\"sign\">+</li>                    \r\n				<li class=\"box\">                        \r\n					<h4>$4 </h4>                        \r\n					<p>Marketplace Fee</p>                    </li>                    \r\n				<li class=\"sign lg-hide\">+</li>                    \r\n				<li class=\"box\">                        \r\n					<h4>15%</h4>                        \r\n					<p>Service Tax</p>                    </li>                    \r\n				<li class=\"sign\">+</li>                    \r\n				<li class=\"box\">                        \r\n					<h4>Amt.</h4>                        \r\n					<p>Amount You Earned</p>                    </li>                    \r\n				<li class=\"sign\">=</li>                    \r\n				<li class=\"box\">                        \r\n					<h4>Price </h4>                        \r\n					<p>Price You Decide</p>                    </li>                \r\n			</ul>            </div>            \r\n		<div class=\"row justify-content-center\">                \r\n			<div class=\"col-lg-6\">                    \r\n				<div class=\"cms text-center mt-5\">                        \r\n					<p>Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum voluptatem.</p>                        <a class=\"link\" href=\"\">Learn More About Pricing</a>                    </div>                </div>            </div>        </div> </div>  '),(17,2,'Seller Page Block 2','     <div class=\"section-head section-head-center\">                        \r\n	<div class=\"section-heading\">                            \r\n		 \r\n		<h2>Simple steps to start selling online</h2>                  </div>                    </div>        \r\n<div class=\"seller-steps\">  \r\n	<ul>      \r\n		<li><i class=\"icn\"><img src=\"/images/easyto-use.png\" alt=\"\" /></i>  \r\n			<h3></h3>\r\n			<h3>Easy to Use</h3>  \r\n			<p>Set up simulation exercises for large group of students in a few steps.</p></li>      \r\n		<li><i class=\"icn\"><img src=\"/images/real-market.png\" alt=\"\" /></i>  \r\n			<h3>Real Market Data</h3>  \r\n			<p>Use real financial markets data in simulation activities.</p></li>      \r\n		<li><i class=\"icn\"><img src=\"/images/simulated.png\" alt=\"\" /></i>  \r\n			<h3>Simulated Market Data</h3>  \r\n			<p>Simulate past market events and data over a specific historical time period.</p></li>      \r\n		<li><i class=\"icn\"><img src=\"/images/customization.png\" alt=\"\" /></i>  \r\n			<h3>Fully Customisable</h3>  \r\n			<p>Fully customize activities to meet various learning outcomes, disciplines and levels of difficulty.</p></li>  \r\n	</ul></div>'),(18,1,'Selling on Yo!Kart is Easy!','Got an established offline store that you want to move online, or just have a passion for selling products online? \r\n\r\nWell, here’s how to take that next step with us. \r\n\r\nAll you will need is:\r\n\r\n1) Legal Shop Details\r\n2) Sales Tax Permit\r\n3) Business Bank Account Details'),(18,2,'Seller Banner Slogan','<h3>Selling on YoKart is easy! <span class=\"\">All you need is:</span> </h3>\r\n<ul>  \r\n	<li><i class=\"fa fa-check\" aria-hidden=\"true\"></i> VAT Number </li>  \r\n	<li><i class=\"fa fa-check\" aria-hidden=\"true\"></i> PAN Card </li>  \r\n	<li><i class=\"fa fa-check\" aria-hidden=\"true\"></i> Current Account Number </li>\r\n</ul>'),(19,1,'Reset Password Right Block','<ul class=\"listing--icons\">   \r\n	<li>   <i class=\"fa fa-truck\"></i>   \r\n		<p><strong>Manage your orders</strong> Easily track orders, Create returns.</p>   </li>   \r\n	<li>   <i class=\"fa fa-bell\"></i>   \r\n		<p><strong>Make  Informed Decisions</strong> Get Relavant alerts and recommendations</p>   </li>   \r\n	<li>   <i class=\"fa fa-thumbs-up\"></i>   \r\n		<p><strong>Engage Socially</strong> With wishlists, Reviews, Ratings</p>   </li>   \r\n</ul>'),(19,2,'Reset Password Right Block','<ul class=\"listing--icons\">\r\n	<li>\r\n		<p><strong>Manage your orders</strong> Easily track orders, Create returns.</p>   </li>\r\n	<li>      \r\n		<p><strong>Make  Informed Decisions</strong> Get Relavant alerts and recommendations</p>   </li>\r\n	<li>      \r\n		<p><strong>Engage Socially</strong> With wishlists, Reviews, Ratings</p>   </li>\r\n</ul>'),(20,1,'Seller side Subscription Package module','\r\n<h3>Simple Pricing With No Surprises</h3>          \r\n<p>Subscription plans and At vero eos et accusamus et iusto odio dignissimos<br />\r\n	            ducimus qui blanditiis quas molestias excepturi sint occaecati cupiditate non provident. </p> '),(20,2,'Simple Pricing With No Surprises','<h3>Simple Pricing With No Surprises</h3>          \r\n<p>Subscription plans and At vero eos et accusamus et iusto odio dignissimos<br />\r\n	ducimus qui blanditiis quas molestias excepturi sint occaecati cupiditate non provident.</p>'),(21,1,'Advertiser with us','YoKart advertising offers a great value to brands with the ability to target their commercial messaging using different categories and search keywords. Our Advertising Platform provides an in-depth knowledge of the e-commerce audience. This will help you to connect with our exclusive user base through various Advertising models like Standard Banners.'),(21,2,'معلن معنا','تقدم إعلانات YoKart قيمة كبيرة للعلامات التجارية مع القدرة على استهداف رسائلها التجارية باستخدام فئات مختلفة وكلمات البحث الرئيسية. توفر منصتنا الإعلانية معرفة متعمقة بجمهور التجارة الإلكترونية. سيساعدك هذا على التواصل مع قاعدة مستخدمينا الحصرية من خلال نماذج إعلانية مختلفة مثل اللافتات القياسية.'),(22,1,'Affiliate program to make money','Our affiliate program is easy &amp; free to join! It enables you to earn revenue by referring potential customers to our website. Whether you are a large content network, social media butterfly or a seasoned blogger, you can earn our standard 5.00% commission on referred purchases. For more information, please visit our FAQ page and donâ€™t forget to read our Terms &amp; Conditions.'),(22,2,'برنامج تابع لكسب المال','برنامجنا التابع سهل ومجاني للانضمام! يمكنك من كسب الإيرادات عن طريق إحالة العملاء المحتملين إلى موقعنا. سواء كنت شبكة محتوى كبيرة أو فراشة وسائل التواصل الاجتماعي أو مدونا متمرسا ، يمكنك كسب عمولة قياسية بنسبة 5.00٪ على المشتريات المشار إليها. لمزيد من المعلومات، يرجى زيارة صفحة الأسئلة الشائعة الخاصة بنا ولا تنس قراءة الشروط والأحكام الخاصة ™بنا.'),(23,1,'Checkout Page Text',''),(23,2,'نص صفحة تشيكوت',''),(24,1,'Seller\'s Registration Page (Block 2)','\r\n<p>Need Help In Getting a Sales Tax Permit?<br />\r\n	<a href=\"http://www.demo.yo-kart.com\" target=\"_blank\" style=\"font-weight: bold;\">Click Here</a> To Contact Our Partners Near Your Location.</p>    '),(24,2,'كن نموذج صفحة البائع نص','\r\n<p>بحاجة إلى مساعدة في الحصول على عموم / ضريبة القيمة المضافة؟<br />\r\n	<a href=\"\" class=\"\">انقر هنا</a> للاتصال بشركائنا بالقرب من موقعك</p>'),(25,1,'Seller\'s Registration Page (Block 5)','\r\n<div class=\"container\"> \r\n	<div class=\"container\">            \r\n		<div class=\"row justify-content-center\">                \r\n			<div class=\"col-lg-9\">                    \r\n				<div class=\"content-wrap\">                        \r\n					<div class=\"content-block\">                            \r\n						<div class=\"content-block-img\">                                <img src=\"./images/sell-onajeebshop.png\" alt=\"\" />                            </div>                            \r\n						<div class=\"content-block-cms\">                                \r\n							<div class=\"cms cms-about-us\">                                    \r\n								<h2>Sell on Yokart!</h2>                                    \r\n								<p>Reach millions of buyers globally.</p>                                </div>                                \r\n							<ul class=\"bullet-circle\">                                    \r\n								<li><i class=\"icn fa fa-check\" aria-hidden=\"true\"></i>                                        \r\n									<p> <strong>Grow your Business</strong> <br />\r\n										                                            Sell to buyers anytime, anywhere\r\n                                        </p>                                    </li>                                    \r\n								<li><i class=\"icn fa fa-check\" aria-hidden=\"true\"></i>                                        \r\n									<p> <strong>Zero Cost</strong> <br />\r\n										 No commission or transaction fee</p>                                    </li>                                    \r\n								<li><i class=\"icn fa fa-check\" aria-hidden=\"true\"></i>                                        \r\n									<p> <strong>Manage your Business Better</strong> <br />\r\n										 Lead Management System &amp; other features</p>                                    </li>                                \r\n							</ul>                            </div>                        </div>                    </div>                </div>            </div>        </div> </div>  '),(25,2,'صفحة البائع بلوك 3','  <div class=\"section-head section-head-center\">                        \r\n	<div class=\"section-heading\">                            \r\n		<h2>Simple Pricing Structure</h2>                        </div>                    </div>\r\n<div class=\"pricing-structure\">  \r\n	<ul>\r\n		<li>10%  \r\n			<p>Commission Fee</p></li>\r\n		<li class=\"sign\">+</li>\r\n		<li>$1  \r\n			<p>Shipping Fee</p></li>\r\n		<li class=\"sign\">+</li>\r\n		<li>$4   \r\n			<p>Marketplace Fee</p></li>\r\n		<li class=\"sign\">+</li>\r\n		<li>15%   \r\n			<p>Service Tax</p></li>\r\n		<li class=\"sign\">+</li>\r\n		<li>Amt.   \r\n			<p>Amount You Earned</p></li>\r\n		<li class=\"sign\">=</li>\r\n		<li>Price   \r\n			<p>Price You Decide</p></li>  \r\n	</ul></div>\r\n<div class=\"align-center\">  \r\n	<p>Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum voluptatem.</p><a href=\"#\" class=\"btn btn-outline-brand mt-4\">Learn More About Pricing</a></div>'),(26,1,'Footer Trust Banners (Only on Homepage)','\r\n<div class=\"container\">            \r\n	<div class=\"incentives-layout-1\">                \r\n		<div class=\"incentives\">                    \r\n			<div class=\"incentives-icon\">                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\" />                    </div>                    \r\n			<h3 class=\"incentives-title\">100% PAYMENT SECURE</h3>                    \r\n			<p class=\"incentives-text\">We ensure secure payment with PEV</p>                </div>                \r\n		<div class=\"incentives\">                    \r\n			<div class=\"incentives-icon\">                        <img src=\"/editor/editor-image/ee622fe6-b1a3-497c-9b91-832630b5688b.png\" width=\"24\" height=\"24\" alt=\"\" style=\"float: none; margin: 0px; width: 29px; height: 28px;\" />                    </div>                    \r\n			<h3 class=\"incentives-title\">FREE SHIPPING</h3>                    \r\n			<p class=\"incentives-text\">Free shipping on all US order or order above $200 </p>                </div>                \r\n		<div class=\"incentives\">                    \r\n			<div class=\"incentives-icon\">                        <img src=\"/editor/editor-image/9b2906a4-bc2e-40a6-b276-4019229d0b86.png\" width=\"24\" height=\"24\" alt=\"\" style=\"float: none; margin: 0px; width: 33px; height: 27px;\" />                    </div>                    \r\n			<h3 class=\"incentives-title\">30 DAYS RETURN</h3>                    \r\n			<p class=\"incentives-text\">Simply return it within 30 days for an exchange.</p>                </div>                \r\n		<div class=\"incentives\">                    \r\n			<div class=\"incentives-icon\">                        <img src=\"/editor/editor-image/1fd16f99-19f7-4ef4-9d7e-d9b8fd715a8b.png\" width=\"24\" height=\"24\" alt=\"\" style=\"float: none; margin: 0px; width: 28px; height: 28px;\" />                    </div>                    \r\n          \r\n			<h3 class=\"incentives-title\">SUPPORT 27/7</h3>                    \r\n			<p class=\"incentives-text\">Contact us 24 hours a day, 7 days a week</p>                </div>            </div>            \r\n        </div> '),(26,2,'لافتات الثقة في التذييل','\r\n<div class=\"container\">            \r\n	<div class=\"incentives-layout-1\">                \r\n		<div class=\"incentives\">                    \r\n			<div class=\"incentives-icon\">                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\" />                    </div>                    \r\n			<h3 class=\"incentives-title\">100% PAYMENT SECURE</h3>                    \r\n			<p class=\"incentives-text\">We ensure secure payment with PEV</p>                </div>                \r\n		<div class=\"incentives\">                    \r\n			<div class=\"incentives-icon\">                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\" />                    </div>                    \r\n			<h3 class=\"incentives-title\">FREE SHIPPING</h3>                    \r\n			<p class=\"incentives-text\">Free shipping on all US order or order above $200 </p>                </div>                \r\n		<div class=\"incentives\">                    \r\n			<div class=\"incentives-icon\">                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\" />                    </div>                    \r\n			<h3 class=\"incentives-title\">30 DAYS RETURN</h3>                    \r\n			<p class=\"incentives-text\">Simply return it within 30 days for an exchange.</p>                </div>                \r\n		<div class=\"incentives\">                    \r\n			<div class=\"incentives-icon\">                        <img src=\"/images/icons/incentives-1.svg\" width=\"24\" height=\"24\" alt=\"\" />                    </div>                    \r\n			<h3 class=\"incentives-title\">100% PAYMENT SECURE</h3>                    \r\n			<p class=\"incentives-text\">We ensure secure payment with PEV</p>                </div>            </div>            \r\n        </div>'),(28,1,'Admin Product Categories','\r\n<h5>Categories Content File</h5>\r\n<h5>Category Identifier</h5>\r\n<p>User defined free text field for unique identifier of the category. This works as a unique key for the system to identify a particular category.</p>\r\n<h5>Parent Identifier</h5>\r\n<p>Parent Identifier is used for categories that belong to a root/master category, essentially they are subcategories to root categories. For a category that is root/master category the parent identifier needs to be left blank.</p>\r\n<h5>Name</h5>\r\n<p>User defined name for the category.</p>\r\n<h5>Description</h5>\r\n<p>User defined description for the category.</p>\r\n<h5>SEO Friendly URL</h5>\r\n<p>User defined URL for the category for SEO purposes. Spaces cannot be used in the URL.</p>\r\n<h5>Featured</h5>\r\n<p>User defined field to mark a particular category as featured or not. Possible inputs for this field are ‘Yes’ &amp; ‘No’.</p>\r\n<h5>Active</h5>\r\n<p>User defined field to mark a particular category as active in the system or not. Possible inputs for this field are ‘Yes’ &amp; ‘No’. Default value should be set as ’Yes’.</p>\r\n<h5>Display Order</h5>\r\n<p>User defined field to set priority on display order of root categories or sub-categories within a root category. If more than one category has display order set to the same value then the system will display category that was added first. If you are unsure about this field add display order as ‘1’ to all the categories.</p>\r\n<h5>Deleted</h5>\r\n<p>User defined field to mark a particular category as deleted in the system or not. Possible inputs for this field are ‘Yes’ &amp; ‘No’. Default value should be set as ’No’ to display categories in the system.</p>\r\n<h5>Categories Media File</h5> \r\n<h5>Category Identifier</h5>\r\n<p>User defined unique identifier for the category. This field needs to be the same as Category Identifier defined in Categories Content sheet.</p>\r\n<h5>Lang Code</h5>\r\n<p>User defined field to link the category image for a particular language. ‘Universal’ is to be used as an option to link the media in all languages. Language codes can be looked up by clicking the language option in the top header. Language codes need to be used if the Category has different images for each language.</p>\r\n<h5>Image Type</h5>\r\n<p>User defined field with input options of ‘Category Icon’ &amp; ‘Category Banner’. Category icon option is to be used when uploading icon image for the category. Category banner option is to be used when uploading banner image for the category page.</p>\r\n<h5>File Path</h5>\r\n<p>File path needs to be a publically accessible URL for example URL’s from Google Drive, Dropbox etc. Images stored locally on your personal device/machine cannot be uploaded. Preferred image dimensions for Category Icon are 60*60 pixels. Preferred image dimensions for Category banner are 1050*340 pixels.</p>\r\n<h5>File Name</h5>\r\n<p>Name of the image file</p>\r\n<h5>Display order</h5>\r\n<p>When a category has multiple images then this field defines the order of display. If you are unsure about this field add display order as ‘1’ to all the categories.</p>'),(29,1,'General Settings','<h3>Multilingual</h3>Since Yo!Kart inherently is a multilingual platform all export-import functionality where ever available in the system will only work for the particular language exported or imported in. This means that a file that is exported in English will only update English values when imported back into the system. Same items in other languages will not be updated until the user exports the same CSV in other languages makes changes and imports it back to the system.<br />\r\n  \r\n<h3>Import/Export process</h3>As a practice it is always recommended to export the CSV first make changes to it and then import it back into the system. This practice will insure accuracy of the CSV file and minimize any errors during import.<br />\r\n  \r\n<h3>Images/Media Files</h3>Any type of images/media can only be imported into the system if the file is located at a public URL. For example the file should be hosted either on a server which is accessible publically or on online tools such as Dropbox/Google Drive etc. Please note that images saved on devices and desktops cannot be imported through the CSV.<br />\r\n Once the media CSV is imported in to the system, a cron job is executed by the system to import and save the images on the server. This cron job is an automated script that the system runs after a set interval on its own and no intervention is required from the users end. The media/images imported into the system will not display immediately.<br />\r\n  \r\n<h3>Deleting Items</h3>Within Yo!Kart when an item is deleted, the system does not actually delete the item from the database rather it just hides the item from display. With the import functionality a user can restore a previously deleted item by changing the value of the deleted column from ‘Yes’ to ‘No’.<br />\r\n   \r\n<h3>Import Log File</h3>Yo!Kart will generate a CSV log file for every import action where it will log the column and row for the errors encountered during the import. If the import was successful then no log file will be generated. System will only allow importing the CSV if no errors are encountered.<br />\r\n  \r\n<h3>CSV</h3>To avoid errors it is absolutely recommended to not alter columns or its names/headers in the CSV. Also to import bulk entries it is absolutely recommended to keep maximum entries to a count of 20,000 per sheet. It is absolutely recommended to make multiple sheets for data above 20,000.<br />\r\n  \r\n<h3>Import Export Yo!Kart Settings</h3>Only turn on/off settings from the settings console if you are familiar with boolean concepts and understand how \'id\'s\' will work in a CSV. Also turning on settings from the import export settings tab may alter or add columns to the CSV. These columns are not defined in the instructions tab.&nbsp;<br />'),(30,1,'Admin Brands','\r\n<h5>Brands Content File</h5>\r\n<h5>Brand Identifier</h5>\r\n<p>User defined unique identifier for the Brand. This works as a unique key for the system to identify a particular Brand. </p>\r\n<h5>Name</h5>\r\n<p>User defined name for the Brand in the system.  </p>\r\n<h5>Description</h5>\r\n<p>User defined description for the Brand. </p>\r\n<h5>SEO Friendly URL</h5>\r\n<p> User defined URL for the Brand for SEO purposes. Spaces cannot be used in the URL.  </p>\r\n<h5>Featured</h5>\r\n<p>User defined field to mark a particular Brand as featured or not. Possible inputs for this field are \'Yes\' &amp; \'No\'.  </p>\r\n<h5>Active</h5>\r\n<p>User defined field to mark a particular category as active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\'.  </p>\r\n<h5>Brands Media File</h5>\r\n<h5>Brand Identifier</h5>\r\n<p>User defined unique identifier for the Brand. This field needs to be the same as Brand Identifier defined in Brands Content sheet.    </p>\r\n<h5>Lang Code</h5>\r\n<p>User defined field to link the brand image for a particular language. \'Universal\' is to be used as an option to link the media in all languages. Language codes can be looked up by clicking the language option in the top header. Language codes need to be used if the Brand has different images for each language.  </p>\r\n<h5>File Path</h5>\r\n<p>File path needs to be a publicly accessible URL for example URL\'s from Google Drive, Dropbox etc. Images stored locally on your personal device/machine cannot be uploaded. Preferred image dimensions are 192*82 pixels. </p>\r\n<h5>File Name</h5>\r\n<p>Name of the image file  </p>\r\n<h5>Display order</h5>\r\n<p>When a brand has multiple images then this field defines the order of display. If you are unsure about this field add display order as \'1\' to all the brands.</p>'),(31,1,'Admin Options','\r\n<h5>Options Content File</h5>\r\n<h5>Option Identifier</h5>\r\n<p>User defined unique identifier for the Option. This works as a unique key for the system to identify a particular Option.</p>\r\n<h5>Option Name</h5>\r\n<p>User defined name for the Option.</p>\r\n<h5>Username</h5>\r\n<p>For admin this field needs to be left blank. In case an option is added by a seller then seller username will be displayed in this field.  </p>\r\n<h5>Is separate image</h5>\r\n<p>User defined input field to denote if the option would have a separate image. Useful for color options of the product. Possible inputs for this field are \'Yes\' &amp; \'No\'.    </p>\r\n<h5>Is color type</h5>\r\n<p>User defined input field to denote if option is a color. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>\r\n<h5>Display in filters</h5>\r\n<p>User defined input field to denote if option is to be displayed in the filters on the product listing page. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>\r\n<h5>Deleted</h5>\r\n<p>User defined field to mark a particular option as deleted in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'No\' to display categories in the system.</p>\r\n<h5>Options Values File</h5>\r\n<h5>Option value identifier</h5>\r\n<p>User defined unique identifier for the Option value. This works as a unique key for the system to identify a particular Option value.</p>\r\n<h5>Option Identifier</h5>\r\n<p>User defined unique identifier for the option. This field value needs to be the same as the Option Identifier defined in Options Content sheet.   </p>\r\n<h5>Option Value</h5>\r\n<p>User defined value for the Option. </p>\r\n<h5>Color code</h5>\r\n<p>User defined Hexadecimal value for the color of the option. Only to be used if the option is a color. Leave this field blank if the option is not a color. Hexadecimal for a color can be searched on Google.  </p>\r\n<h5>Display order</h5>\r\n<p>When an option has multiple option values then this field defines the order of display of the option value. If you are unsure about this field add display order as \'1\'.</p>'),(32,1,'Admin Tags','\r\n<h5>Tags Content File</h5> \r\n<h5>Tag Identifier</h5>\r\n<p>User defined unique identifier for the Tag. This works as a unique key for the system to identify a particular Tag.</p>\r\n<h5>Username</h5>\r\n<p>For admin this field needs to be left blank. In case a tag is added by a seller then seller username will be displayed in this field.</p>\r\n<h5>Tag name</h5>\r\n<p>User defined name for the Tag.</p>'),(33,1,'Admin Countries Management','\r\n<h5>Countries Content File</h5>\r\n<h5>Country Code</h5>\r\n<p>User defined field for unique country code.</p>\r\n<h5>Country Name</h5>\r\n<p>User defined field for unique country name.</p>\r\n<h5>Currency Code</h5>\r\n<p>User defined field for unique currency code for the country.</p>\r\n<h5>Language Code</h5>\r\n<p>Language code for the country can be input here. \'Universal\' is to be used as an option if there is no preference, else relevant language code needs to be associated with the country. For example we will use \'ENG\' for the United States.</p>\r\n<h5>Active</h5>\r\n<p>User defined field to mark a particular country as active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\'.</p>'),(34,1,'Admin State Management','\r\n<h5>States Content File</h5>  \r\n<h5>State Identifier</h5>\r\n<p>User defined unique identifier for the State. This works as a unique key for the system to identify a particular State.</p>\r\n<h5>Country Code</h5>\r\n<p>This field needs to be the same as country code defined in Countries Content sheet.</p>\r\n<h5>Sate Name</h5>\r\n<p>User defined field for unique state name.</p>\r\n<h5>State Code</h5>\r\n<p>User defined field for unique state code.</p>\r\n<h5>Active</h5>\r\n<p>User defined field to mark a particular state as active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\'.</p>'),(35,1,'Admin Manage Catalog','<div class=\"grouplisting\">                             \r\n	<div class=\"groups group-js\">                                 \r\n		<div class=\"group__head group__head-js\"> \r\n			<h5> Product Catalog Content </h5></div>                                 \r\n		<div class=\"group__body group__body-js\">                                     \r\n			<h5>Product Identifier</h5>                                     \r\n			<p>User defined unique identifier for the Product. This works as a unique key for the system to identify a particular Product.</p>                                     \r\n			<h5>Username</h5>                                     \r\n			<p>For admin this field needs to be left blank. In case an option is added by a seller then seller username will be displayed in this field.  </p>                                     \r\n			<h5>Name</h5>                                     \r\n			<p>User defined field for product name.</p>                                     \r\n			<h5>Description</h5>                                     \r\n			<p>User defined field for product description. </p>                                     \r\n			<h5>Youtube video</h5>                                     \r\n			<p>User defined field for product Youtube video URL</p>                                     \r\n			<h5>Category Identifier</h5>                                     \r\n			<p> User defined unique identifier for the category. This field needs to be the same as Category Identifier defined in Categories Content sheet.  </p>                                     \r\n			<h5>Brand Identifier</h5>                                     \r\n			<p>User defined unique identifier for the Brand. This field needs to be the same as Brand Identifier defined in Brand Content sheet.  </p>                                     \r\n			<h5>Product Type Identifier</h5>                                     \r\n			<p>User defined input field to denote the type of the Product. Possible inputs for this field are \'Physical\' &amp; \'Digital\'. </p>                                     \r\n			<h5>Model</h5>                                     \r\n			<p>User defined field for product model.</p>                                     \r\n			<h5>Minimum selling price</h5>                                     \r\n			<p>User defined field for minimum selling price for the product.</p>                                     \r\n			<h5>Tax Category Identifier</h5>                                     \r\n			<p>User defined unique identifier for the Tax category. This field needs to be the same as Tax Category Identifier defined in the Admin console under the Sales Tax option page.</p>                                     \r\n			<h5>Length</h5>                                     \r\n			<p>User defined field for product package length.</p>                                     \r\n			<h5>Width</h5>                                     \r\n			<p>User defined field for product package width.</p>                                                                          \r\n			<h5>Height</h5>                                     \r\n			<p>User defined field for product package Height.</p>                                                                          \r\n			<h5>Dimension Unit Identifier</h5>                                     \r\n			<p>User defined input field to denote the unit of the dimensions of the package. Possible inputs for this field are \'Inch\', \'Centimeter\' &amp; \'Feet\'. </p>                                                                          \r\n			<h5>Weight </h5>                                     \r\n			<p>User defined field for product package Weight.</p>                                     \r\n			<h5>Weight Unit Identifier</h5>                                     \r\n			<p>User defined input field to denote the unit of the weight of the package. . Possible inputs for this field are \'Gram\', \'Kilogram\' &amp; \'Pound\'.</p>                                     \r\n			<h5>Ean/upc Code</h5>                                     \r\n			<p>User defined field for EAN/UPC code of the product.</p>                                     \r\n			<h5>Shipping country Code</h5>                                     \r\n			<p>This field needs to be the same as country code defined in Countries Content sheet.  </p>                                     \r\n			<h5>Added On</h5>                                     \r\n			<p>User defined field for product add date to the system.</p>                                     \r\n			<h5>Free Shipping</h5>                                     \r\n			<p>User defined field to mark a particular Product is available for free shipping. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>                                     \r\n			<h5>COD Available</h5>                                     \r\n			<p>User defined field to mark a particular Product is available for Cash on Delivery or not. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>                                     \r\n			<h5>Featured</h5>                                     \r\n			<p>User defined field to mark a particular Product as featured or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. </p>                                     \r\n			<h5>Approved</h5>                                     \r\n			<p>User defined field to mark a particular Product as Approved or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\' to display products in the system.</p>                                     \r\n			<h5>Active</h5>                                     \r\n			<p>User defined field to mark a particular Product as active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\'. </p>                                     \r\n			<h5>Deleted</h5>                                     \r\n			<p>User defined field to mark a particular product as deleted in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'No\' to display products in the system. </p>                                </div>                            </div>                             \r\n	<div class=\"groups group-js\">                                 \r\n		<div class=\"group__head group__head-js\"> \r\n			<h5> Product Option Content </h5></div>                                 \r\n		<div class=\"group__body group__body-js\">                                     \r\n			<ul>                                                                              \r\n				<li>                                                                                      \r\n					<h5>Product Identifier</h5>                                                                                      \r\n					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet. </p>                                    </li>                                                                              \r\n				<li>                                                                                      \r\n					<h5>Option Identifier</h5>                                                                                      \r\n					<p>User defined unique identifier for the Option. This field needs to be the same as Option Identifier defined in Option Content sheet. </p>                                        </li>                                                                      \r\n			</ul>                                </div>                            </div>                             \r\n	<div class=\"groups group-js\">                                 \r\n		<div class=\"group__head group__head-js\"> \r\n			<h5> Product Tag Content</h5></div>                                 \r\n		<div class=\"group__body group__body-js\">                                     \r\n			<ul>                                                                              \r\n				<li>                                                                                      \r\n					<h5>Product Identifier</h5>                                                                                      \r\n					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet.</p>                                    </li>                                                                              \r\n				<li>                                                                                      \r\n					<h5>Tag Identifier</h5>                                                                                      \r\n					<p>User defined unique identifier for the Tag. This field needs to be the same as Tag Identifier defined in Tag Content sheet. </p>                                    </li>                                                                      \r\n			</ul>                                </div>                            </div>                             \r\n	<div class=\"groups group-js\">                                 \r\n		<div class=\"group__head group__head-js\"> \r\n			<h5> Product Specification Content </h5></div>                                 \r\n		<div class=\"group__body group__body-js\">                                     \r\n			<ul>                                                                              \r\n				<li>                                                                                      \r\n					<h5>Product Identifier</h5>                                                                                      \r\n					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet.    </p>                                    </li>                                                                              \r\n				<li>                                                                                      \r\n					<h5>Lang Code</h5>                                                                                      \r\n					<p>User defined field to link the product specification for a particular language. Language codes can be looked up by clicking the language option in the top header. </p>                                    </li>                                                                              \r\n				<li>                                                                                      \r\n					<h5>Specification Name</h5>                                                                                      \r\n					<p>User defined field for product specification name.</p>                                    </li>                                                                              \r\n				<li>                                                                                      \r\n					<h5>Specification Value</h5>                                                                                      \r\n					<p>User defined field for product specification Value.</p>                                    </li>                                                                      \r\n			</ul>                                </div>                            </div>                             \r\n	<div class=\"groups group-js\">                                 \r\n		<div class=\"group__head group__head-js\"> \r\n			<h5> Product Shipping Content </h5></div>                                 \r\n		<div class=\"group__body group__body-js\">                                     \r\n			<ul>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Product Identifier</h5>                                                                                  \r\n					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet.</p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Username</h5>                                                                                  \r\n					<p>For admin this field needs to be left blank. In case an option is added by a seller then seller username will be displayed in this field. </p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Shipping Country Code</h5>                                                                                  \r\n					<p>This field needs to be the same as country code defined in Countries Content sheet. This field can be left blank if the product has no restrictions on the countries it is shipped to.</p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Shipping Company Identifier</h5>                                                                                  \r\n					<p>User defined unique identifier for the Shipping company identifier. This field needs to be the same as the Shipping Company Identifier defined in the Admin console>Shipping API>Shipping Companies page.  </p>                                        </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Shipping Duration Identifier</h5>                                                                                  \r\n					<p>User defined unique identifier for the Shipping Duration identifier. This field needs to be the same as the Shipping Duration Identifier defined in the Admin console>Shipping API>Duration Labels page. </p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Cost</h5>                                                                                  \r\n					<p>User defined field for product shipping cost.</p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Additional Item Cost</h5>                                                                                  \r\n					<p>User defined field for additional shipping cost per product.</p>                                    </li>                                                                  \r\n			</ul>                                </div>                            </div>                             \r\n	<div class=\"groups group-js\">                                 \r\n		<div class=\"group__head group__head-js\"> \r\n			<h5> Product Catalog Media  </h5></div>                                 \r\n		<div class=\"group__body group__body-js\">                                     \r\n			<ul>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Product Identifier</h5>                                                                                  \r\n					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet. </p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Lang Code</h5>                                                                                  \r\n					<p>User defined field to link the product image for a particular language. \'Universal\' is to be used as an option to link the media in all languages. Language codes can be looked up by clicking the language option in the top header. Language codes need to be used if the Product has different images for each language.</p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Option Identifier</h5>                                                                                  \r\n					<p>User defined unique identifier for the option. This field value needs to be the same as the Option Identifier defined in Options Content sheet.   </p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Option value Identifier</h5>                                                                                  \r\n					<p>User defined unique identifier for the option value. This field value needs to be the same as the Option value Identifier defined in Options Value Content sheet. </p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>File Path</h5>                                                                                  \r\n					<p>File path needs to be a publically accessible URL for example URL\'s from Google Drive, Dropbox etc. Images stored locally on your personal device/machine cannot be uploaded. Preferred image dimensions for the product images are greater than 500*500 pixels. </p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>File Name</h5>                                                                                  \r\n					<p>Name of the image file. </p>                                    </li>                                                                          \r\n				<li>                                                                                  \r\n					<h5>Display order</h5>                                                                                  \r\n					<p>When a product has multiple images then this field defines the order of display. If you are unsure about this field add display order as \'1\'. </p>                                    </li>                                                                  \r\n			</ul>                                </div>                            </div>                        </div>'),(36,1,'Seller Manage Catalog','\r\n<div class=\"grouplisting\">    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Catalog – Product Catalog </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Product Identifier </h5>                    \r\n					<p>User defined unique identifier for the Product. This works as a unique key for the system to identify a particular Product.</p>                </li>                \r\n				<li>                    \r\n					<h5>Username </h5>                    \r\n					<p>For admin this field needs to be left blank. In case a product is added by a seller then seller username will be displayed in this field.  </p>                </li>                \r\n				<li>                    \r\n					<h5>Name </h5>                    \r\n					<p>User defined field for product name.</p>                </li>                \r\n				<li>                    \r\n					<h5>Description </h5>                    \r\n					<p>User defined field for product description. er</p>                </li>                \r\n				<li>                    \r\n					<h5>Youtube video</h5>                    \r\n					<p>User defined field for product Youtube video URL. </p>                </li>                \r\n				<li>                    \r\n					<h5>Category Identifier</h5>                    \r\n					<p>User defined unique identifier for the category. This field needs to be the same as the Category Identifier defined in Categories export sheet.   </p>                </li>                \r\n				<li>                    \r\n					<h5>Brand Identifier</h5>                    \r\n					<p>User defined unique identifier for the Brand. This field needs to be the same as Brand Identifier defined in Brand  sheet.   </p>                </li>                \r\n				<li>                    \r\n					<h5>Product Type Identifier</h5>                    \r\n					<p>User defined input field to denote the type of the Product. Possible inputs for this field are \'Physical\' &amp; \'Digital\'. </p>                </li>                \r\n				<li>                    \r\n					<h5>Model </h5>                    \r\n					<p>User defined field for product model.</p>                </li>                \r\n				<li>                    \r\n					<h5>Minimum selling price</h5>                    \r\n					<p>User defined field for minimum selling price for the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>Tax Category Identifier</h5>                    \r\n					<p>User defined unique identifier for the Tax category. This field needs to be the same as Tax Category Identifier defined in tax category export sheet.   </p>                </li>                \r\n				<li>                    \r\n					<h5>Length</h5>                    \r\n					<p>User defined field for product package length.</p>                </li>                \r\n				<li>                    \r\n					<h5>Width</h5>                    \r\n					<p>User defined field for product package width.</p>                </li>                \r\n				<li>                    \r\n					<h5>Height</h5>                    \r\n					<p>User defined field for product package Height.</p>                </li>                \r\n				<li>                    \r\n					<h5>Dimension Unit Identifier </h5>                    \r\n					<p> User defined input field to denote the unit of the dimensions of the package. Possible inputs for this field are \'Inch\', \'Centimeter\' &amp; \'Feet\'.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Weight </h5>                    \r\n					<p>User defined field for product package Weight.</p>                </li>                \r\n				<li>                    \r\n					<h5>Weight Unit Identifier</h5>                    \r\n					<p>User defined input field to denote the unit of the weight of the package. . Possible inputs for this field are \'Gram\', \'Kilogram\' &amp; \'Pound\'. </p>                </li>                \r\n				<li>                    \r\n					<h5>Ean/upc Code</h5>                    \r\n					<p>User defined field for EAN/UPC code of the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>Shipping country Code</h5>                    \r\n					<p>This field needs to be the same as country code defined in Countries export sheet.   </p>                </li>                \r\n				<li>                    \r\n					<h5>Free Shipping </h5>                    \r\n					<p>User defined field to mark a particular Product is available for free shipping. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>                </li>                \r\n				<li>                    \r\n					<h5>COD Available</h5>                    \r\n					<p>User defined field to mark a particular Product is available for Cash on Delivery or not. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>                </li>                \r\n				<li>                    \r\n					<h5>Featured</h5>                    \r\n					<p>User defined field to mark a particular Product as featured or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. </p>                </li>                \r\n				<li>                    \r\n					<h5>Approved </h5>                    \r\n					<p>User defined field to mark a particular Product as Approved or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\' to display products in the system.</p>                </li>                \r\n				<li>                    \r\n					<h5>Active </h5>                    \r\n					<p>User defined field to mark a particular Product as active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\'. </p>                </li>                \r\n				<li>                    \r\n					<h5>Deleted </h5>                    \r\n					<p>User defined field to mark a particular product as deleted in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'No\' to display products in the system. </p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Catalog - Product Option </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Product Identifier</h5>                    \r\n					<p> User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Option Identifier</h5>                    \r\n					<p>User defined unique identifier for the Option. This field needs to be the same as Option Identifier defined in Option export sheet.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Catalog - Product Tags</h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Product Identifier</h5>                    \r\n					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Tag Identifier</h5>                    \r\n					<p>User defined unique identifier for the Tag. This field needs to be the same as tag Identifier defined in tags export sheet.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Catalog - Product Specifications</h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Product Identifier</h5>                    \r\n					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Lang Code</h5>                    \r\n					<p>User defined field to link the product specification for a particular language. Language codes can be looked up by clicking the language option in the top header. </p>                </li>                \r\n				<li>                    \r\n					<h5>Specification Name</h5>                    \r\n					<p>User defined field for product specification name.</p>                </li>                \r\n				<li>                    \r\n					<h5>Specification Value</h5>                    \r\n					<p>User defined field for product specification Value.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Catalog - Product Shipping</h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Product Identifier</h5>                    \r\n					<p> User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Username</h5>                    \r\n					<p>For admin this field needs to be left blank. In case an option is added by a seller then seller username will be displayed in this field.  </p>                </li>                \r\n				<li>                    \r\n					<h5>Shipping Country Code</h5>                    \r\n					<p>This field needs to be the same as country code defined in the Countries export sheet. </p>                </li>                \r\n				<li>                    \r\n					<h5>Shipping Company Identifier</h5>                    \r\n					<p>User defined unique identifier for the Shipping company identifier. This field needs to be the same as the Shipping Company Identifier defined in the Admin console>Shipping API>Shipping Companies page. Please contact the admin for details.     </p>                </li>                \r\n				<li>                    \r\n					<h5>Shipping Duration Identifier</h5>                    \r\n					<p>User defined unique identifier for the Shipping Duration identifier. This field needs to be the same as the Shipping Duration Identifier defined in the Admin console>Shipping API>Duration Labels page. Please contact the admin for details.</p>                </li>                \r\n				<li>                    \r\n					<h5>Cost</h5>                    \r\n					<p>User defined field for product shipping cost.</p>                </li>                \r\n				<li>                    \r\n					<h5>Additional Item Cost </h5>                    \r\n					<p>User defined field for additional shipping cost per product.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Catalog - Product Media</h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Product Identifier</h5>                    \r\n					<p>User defined unique identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Lang Code</h5>                    \r\n					<p>User defined field to link the image for a particular language. \'Universal\' is to be used as an option to link the media in all languages. Language codes can be looked up by clicking the language option in the top header. Language codes need to be used if the product has different images for each language.</p>                </li>                \r\n				<li>                    \r\n					<h5>Option Identifier</h5>                    \r\n					<p>User defined unique identifier for the Option. This field needs to be the same as Option Identifier defined in Option export sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Option Value Identifier</h5>                    \r\n					<p>User defined unique identifier for the Option value. This field needs to be the same as the Option value Identifier defined in the Option value export sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>File Path</h5>                    \r\n					<p>File path needs to be a publically accessible URL for example URL\'s from Google Drive, Dropbox etc. Images stored locally on your personal device/machine cannot be uploaded.</p>                </li>                \r\n				<li>                    \r\n					<h5>File Name</h5>                    \r\n					<p>Name of the image file</p>                </li>                \r\n				<li>                    \r\n					<h5>Display order</h5>                    \r\n					<p>When a product has multiple images then this field defines the order of display. If you are unsure about this field add display order as \'1\'. </p>                </li>            \r\n			</ul>        </div>    </div></div>'),(37,1,'Seller Import Export General Settings','<h5>Multilingual</h5>\r\n<p>Since Yo!Kart inherently is a multilingual platform all export-import functionality where ever available in the system will only work for the particular language exported or imported in. This means that a file that is exported in English will only update English values when imported back into the system. Same items in other languages will not be updated until the user exports the same CSV in other languages makes changes and imports it back to the system.</p>\r\n<h5>Import/Export process</h5>\r\n<p>As a practice it is always recommended to export the CSV first make changes to it and then import it back into the system. This practice will insure accuracy of the CSV file and minimize any errors during import.</p>\r\n<h5>Images/Media Files</h5>\r\n<p>Any type of images/media can only be imported into the system if the file is located at a public URL. For example the file should be hosted either on a server which is accessible publically or on online tools such as Dropbox/Google Drive etc. Please note that images saved on devices and desktops cannot be imported through the CSV.<br />\r\n	Once the media CSV is imported in to the system, a cron job is executed by the system to import and save the images on the server. This cron job is an automated script that the system runs after a set interval on its own and no intervention is required from the users end. The media/images imported into the system will not display immediately.</p>\r\n<h5>Deleting Items</h5>\r\n<p>Within Yo!Kart when an item is deleted, the system does not actually delete the item from the database rather it just hides the item from display. With the import functionality a user can restore a previously deleted item by changing the value of the deleted column from Yes to No.</p>\r\n<h5>Import Log File</h5>\r\n<p>Yo!Kart will generate a CSV log file for every import action where it will log the column and row for the errors encountered during the import. If the import was successful then no log file will be generated. System will only allow importing the CSV if no errors are encountered.</p>\r\n<h5>CSV</h5>\r\n<p>To avoid errors it is absolutely recommended to not alter columns or its names/headers in the CSV. Also to import bulk entries it is absolutely recommended to keep maximum entries to a count of 20,000 per sheet. It is absolutely recommended to make multiple sheets for data above 20,000.</p>\r\n<h5>Import Export Yo!Kart Settings</h5>\r\n<p>Only turn on/off settings from the settings console if you are familiar with boolean concepts and understand how id\'s will work in a CSV. Also turning on settings from the import export settings tab may alter or add columns to the CSV. These columns are not defined in the instructions tab.</p>'),(38,1,'Products Inventory - Admin','\r\n<div class=\"grouplisting\">    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – General Data  </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined unique id for the Product. This field needs to be unique.</p>                </li>                \r\n				<li>                    \r\n					<h5>Product Identifier</h5>                    \r\n					<p>User defined identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog Content sheet. </p>                </li>                \r\n				<li>                    \r\n					<h5>Username</h5>                    \r\n					<p>Username of the seller to which inventory is being updated.</p>                </li>                \r\n				<li>                    \r\n					<h5>Selling price</h5>                    \r\n					<p>Selling price of the product </p>                </li>                \r\n				<li>                    \r\n					<h5>Stock</h5>                    \r\n					<p>Quantity available for the product </p>                </li>                \r\n				<li>                    \r\n					<h5>Min Order Quantity</h5>                    \r\n					<p>Minimum quantity that a buyer can purchase for the product</p>                </li>                \r\n				<li>                    \r\n					<h5>Subtract Stock</h5>                    \r\n					<p>User defined field to mark if the system should subtract stock or not once an order is placed. Possible inputs for this field are \'Yes\' &amp; \'No\'.</p>                </li>                \r\n				<li>                    \r\n					<h5>Track Inventory</h5>                    \r\n					<p>User defined field to mark if the system should monitor inventory or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. </p>                </li>                \r\n				<li>                    \r\n					<h5>Threshold Stock Level</h5>                    \r\n					<p>User defined field to input threshold stock level upon which the system would generate an alert email. This will only work if both Subtract Stock &amp; Track Inventory are set as \'Yes\'.</p>                </li>                \r\n				<li>                    \r\n					<h5>Condition identifier</h5>                    \r\n					<p> User defined field to define a particular product\'s condition in the system. Possible inputs for this field are \'New\', \'Used\' &amp; \'Refurbished\'.</p>                </li>                \r\n				<li>                    \r\n					<h5>Digital Product Max Download time</h5>                    \r\n					<p>User defined field to define maximum number of times a digital product can be downloaded. Possible inputs for this field are integers.</p>                </li>                \r\n				<li>                    \r\n					<h5>Download validity in days</h5>                    \r\n					<p>User defined field to define maximum number of days until the digital product can be downloaded. Possible inputs for this field are integers.</p>                </li>                \r\n				<li>                    \r\n					<h5>Title</h5>                    \r\n					<p>User defined field to define the title of the product in the shop. </p>                </li>                \r\n				<li>                    \r\n					<h5>Comments</h5>                    \r\n					<p> User defined field to input comments for the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>URL Keyword</h5>                    \r\n					<p>User defined field for input of URL keywords, used for URL rewriting.&nbsp;&nbsp;</p>                </li>                \r\n				<li>                    \r\n					<h5>Added on </h5>                    \r\n					<p>User defined date field to input the date the product is added into the system. Date format is mm/dd/yy</p>                </li>                \r\n				<li>                    \r\n					<h5>Available from </h5>                    \r\n					<p> User defined date field to input the date the product is available from. Date format is mm/dd/yy</p>                </li>                \r\n				<li>                    \r\n					<h5>Active</h5>                    \r\n					<p>User defined field to mark a particular product as Active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\' to display products in the system.</p>                </li>                \r\n				<li>                    \r\n					<h5>COD Available</h5>                    \r\n					<p>User defined field to mark a particular product is available for cash on delivery in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. </p>                </li>                \r\n				<li>                    \r\n					<h5>Deleted</h5>                    \r\n					<p>User defined field to mark a particular product as deleted in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'No\' to display products in the system.</p>                </li>                \r\n				<li>                    \r\n					<h5>Sold count</h5>                    \r\n					<p>System defined field to show the user cold count for a particular product. This field cannot be updated by the user.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Product Options  </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id </h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Option Identifier</h5>                    \r\n					<p>User defined unique identifier for the Option. This field needs to be the same as the option identifier defined in the Options content sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Option Value Identifier</h5>                    \r\n					<p>User defined unique identifier for the Option value. This field needs to be the same as the option value identifier defined in the Options value content sheet.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – SEO Data </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.  </p>                </li>                \r\n				<li>                    \r\n					<h5>Meta Identifier</h5>                    \r\n					<p>User defined unique identifier for the Meta data. This works as a unique key for the system to identify a particular Meta data.</p>                </li>                \r\n				<li>                    \r\n					<h5>Meta Title</h5>                    \r\n					<p>User defined input field for the user to define Meta title for the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>Meta Keywords</h5>                    \r\n					<p>User defined input field for the user to define Meta keywords for the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>Meta Description</h5>                    \r\n					<p>User defined input field for the user to define Meta Description for the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>Other Meta Tags </h5>                    \r\n					<p>User defined input field for the user to define other Meta tags for the product.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Special Price</h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id </h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.  </p>                </li>                \r\n				<li>                    \r\n					<h5>Start Date</h5>                    \r\n					<p>User defined date field to input the date from which the special price of the product starts from. Date format is mm/dd/yy</p>                </li>                \r\n				<li>                    \r\n					<h5>End Date</h5>                    \r\n					<p>User defined date field to input the date from which the special price of the product ends on. Date format is mm/dd/yy</p>                </li>                \r\n				<li>                    \r\n					<h5>Price</h5>                    \r\n					<p>User defined field for special price of the product. </p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Volume Discount </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Min Quantity</h5>                    \r\n					<p>User defined field for minimum quantity of the product to be purchased for volume discount.</p>                </li>                \r\n				<li>                    \r\n					<h5>Discount Percentage</h5>                    \r\n					<p>User defined field for discount percentage to be applied to the product in case of the volume discount. </p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Buy Together </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Buy Together Selprod Id</h5>                    \r\n					<p>User defined product identifier for the buy together related Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Related Products </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Related Selprod Id</h5>                    \r\n					<p>User defined product identifier for the related Products. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Seller Product Policy  </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id </h5>                    \r\n					<p> User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Policy Point Identifier</h5>                    \r\n					<p>User defined policy point identifier for the Product. This field needs to be the same as the policy point identifier defined on the Policy Points Management page under the CMS tab in the admin console. </p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Media  </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Lang Code</h5>                    \r\n					<p>User defined field to link the image for a particular language. \'Universal\' is to be used as an option to link the media in all languages. Language codes can be looked up by clicking the language option in the top header. Language codes need to be used if the product has different images for each language.</p>                </li>                \r\n				<li>                    \r\n					<h5>File Path</h5>                    \r\n					<p>File path needs to be a publically accessible URL for example URL\'s from Google Drive, Dropbox etc. Images stored locally on your personal device/machine cannot be uploaded.</p>                </li>                \r\n				<li>                    \r\n					<h5>File Name</h5>                    \r\n					<p>Name of the image file </p>                </li>                \r\n				<li>                    \r\n					<h5>Display order</h5>                    \r\n					<p>When a product has multiple images then this field defines the order of display. If you are unsure about this field add display order as \'1\'.</p>                </li>            \r\n			</ul>        </div>    </div></div>'),(39,1,'Products Inventory - Seller','\r\n<div class=\"grouplisting\">    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – General Data </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined unique id for the Product. This field needs to be unique.</p>                </li>                \r\n				<li>                    \r\n					<h5>Product Identifier</h5>                    \r\n					<p>User defined identifier for the Product. This field needs to be the same as Product Identifier defined in the Product Catalog sheet.  </p>                </li>                \r\n				<li>                    \r\n					<h5>Selling price </h5>                    \r\n					<p>Selling price of the product</p>                </li>                \r\n				<li>                    \r\n					<h5>Stock</h5>                    \r\n					<p>Quantity available for the product </p>                </li>                \r\n				<li>                    \r\n					<h5>Min Order Quantity</h5>                    \r\n					<p>Minimum quantity that a buyer can purchase for the product</p>                </li>                \r\n				<li>                    \r\n					<h5>Subtract Stock</h5>                    \r\n					<p>User defined field to mark if the system should subtract stock or not once an order is placed. Possible inputs for this field are \'Yes\' &amp; \'No\'. </p>                </li>                \r\n				<li>                    \r\n					<h5>Track Inventory</h5>                    \r\n					<p> User defined field to mark if the system should monitor inventory or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. </p>                </li>                \r\n				<li>                    \r\n					<h5>Threshold Stock Level </h5>                    \r\n					<p>User defined field to input threshold stock level upon which the system would generate an alert email. This will only work if both Subtract Stock &amp; Track Inventory are set as \'Yes\'.</p>                </li>                \r\n				<li>                    \r\n					<h5>Condition identifier </h5>                    \r\n					<p>User defined field to define a particular product\'s condition in the system. Possible inputs for this field are \'New\', \'Used\' &amp; \'Refurbished\'.</p>                </li>                \r\n				<li>                    \r\n					<h5>Digital Product Max Download time</h5>                    \r\n					<p>User defined field to define maximum number of times a digital product can be downloaded. Possible inputs for this field are integers.</p>                </li>                \r\n				<li>                    \r\n					<h5>Download validity in days</h5>                    \r\n					<p>User defined field to define maximum number of days until the digital product can be downloaded. Possible inputs for this field are integers.</p>                </li>                \r\n				<li>                    \r\n					<h5>Title </h5>                    \r\n					<p>User defined field to define the title of the product in the shop. </p>                </li>                \r\n				<li>                    \r\n					<h5>Comments</h5>                    \r\n					<p>User defined field to input comments for the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>URL Keyword</h5>                    \r\n					<p>&nbsp;User defined field for input of URL keywords, used for URL rewriting.&nbsp;&nbsp;</p>                </li>                \r\n				<li>                    \r\n					<h5>Available from</h5>                    \r\n					<p>User defined date field to input the date the product is available from. Date format is mm/dd/yy</p>                </li>                \r\n				<li>                    \r\n					<h5>Active</h5>                    \r\n					<p>User defined field to mark a particular product as Active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\' to display products in the system.</p>                </li>                \r\n				<li>                    \r\n					<h5>COD Available</h5>                    \r\n					<p>User defined field to mark a particular product is available for cash on delivery in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. </p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Product Options</h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Option Identifier</h5>                    \r\n					<p>User defined unique identifier for the Option. This field needs to be the same as Option Identifier defined in Option export sheet. </p>                </li>                \r\n				<li>                    \r\n					<h5>Option Value Identifier</h5>                    \r\n					<p>User defined unique identifier for the Option value. This field needs to be the same as Option Value Identifier defined in Option Value export sheet.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – SEO</h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id </h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.    </p>                </li>                \r\n				<li>                    \r\n					<h5>Meta Identifier</h5>                    \r\n					<p>User defined unique identifier for the Meta data. This works as a unique key for the system to identify a particular Meta data.</p>                </li>                \r\n				<li>                    \r\n					<h5>Meta Title</h5>                    \r\n					<p>User defined input field for the user to define Meta title for the product. </p>                </li>                \r\n				<li>                    \r\n					<h5>Meta Keywords</h5>                    \r\n					<p>User defined input field for the user to define Meta keywords for the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>Meta Description</h5>                    \r\n					<p>User defined input field for the user to define Meta Description for the product.</p>                </li>                \r\n				<li>                    \r\n					<h5>Other Meta Tags </h5>                    \r\n					<p>User defined input field for the user to define other Meta tags for the product.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Special Price </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Start Date</h5>                    \r\n					<p>User defined date field to input the date from which the special price of the product starts from. Date format is mm/dd/yy</p>                </li>                \r\n				<li>                    \r\n					<h5>End Date</h5>                    \r\n					<p>User defined date field to input the date from which the special price of the product ends on. Date format is mm/dd/yy</p>                </li>                \r\n				<li>                    \r\n					<h5>Price</h5>                    \r\n					<p>User defined field for special price of the product. </p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Volume Discount </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Min Quantity </h5>                    \r\n					<p>User defined field for minimum quantity of the product to be purchased for volume discount.</p>                </li>                \r\n				<li>                    \r\n					<h5>Discount Percentage </h5>                    \r\n					<p>User defined field for discount percentage to be applied to the product in case of the volume discount. </p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Buy Together </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id </h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Buy Together Selprod Id</h5>                    \r\n					<p>User defined product identifier for the buy together related Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5>  Seller Products – Related Products</h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Related Selprod Id</h5>                    \r\n					<p>User defined product identifier for the related Products. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.  </p>                </li>            \r\n			</ul>        </div>    </div>    \r\n	<div class=\"groups group-js\">        \r\n		<div class=\"group__head group__head-js\">            \r\n			<h5> Seller Products – Seller Product Policy </h5>        </div>        \r\n		<div class=\"group__body group__body-js\">            \r\n			<ul>                \r\n				<li>                    \r\n					<h5>Seller Product Id</h5>                    \r\n					<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>                </li>                \r\n				<li>                    \r\n					<h5>Policy Point Identifier </h5>                    \r\n					<p> User defined policy point identifier for the Product. This field needs to be the same as the policy point identifier defined on the Policy Points Management page under the CMS tab in the admin console. </p>                </li>            \r\n			</ul>        </div>    </div></div>'),(40,1,'Product Inventory Update Instructions','<h5>Seller Product Id</h5>\r\n<p>User defined product identifier for the Product. This field needs to be the same as the seller product identifier defined in the Seller Product General Data sheet.</p>\r\n<h5>SKU</h5>\r\n<p>User defined field for the product SKU.</p>\r\n<h5>Product</h5>\r\n<p>User defined field for the product name.</p>\r\n<h5>Price</h5>\r\n<p>User defined field for the product price.</p>\r\n<h5>Stock/quantity</h5>\r\n<p>User defined field for the stock/quantity of the product.</p>'),(45,1,'Master Product Instructions (Seller>Master Products)','    Marketplace products are product catalogs added by the admin. A product catalog is a type of marketing collateral that lists essential product details including product features, descriptions, dimensions, maximum price, weight, availability, color, and more.'),(45,2,'تعليمات منتج السوق','منتجات <span style=\"color:\" rgb(32,=\" 33,=\" 36);=\" font-family:=\" arial,=\" sans-serif;=\" font-size:=\" 16px;=\" background-color:=\" rgb(255,=\" 255,=\" 255);\"=\">السوق هي كتالوجات منتجات يضيفها المسؤول. كتالوج المنتجات هو&nbsp;</span><span style=\"color:\" rgb(32,=\" 33,=\" 36);=\" font-family:=\" arial,=\" sans-serif;=\" font-size:=\" 16px;=\" background-color:=\" rgb(255,=\" 255,=\" 255);\"=\">نوع من الضمانات التسويقية التي تسرد تفاصيل المنتج الأساسية بما في ذلك</span><span style=\"color:\" rgb(32,=\" 33,=\" 36);=\" font-family:=\" arial,=\" sans-serif;=\" font-size:=\" 16px;=\" background-color:=\" rgb(255,=\" 255,=\" 255);\"=\"\">&nbsp;ميزات المنتج والأوصاف والأبعاد والحد الأقصى للسعر والوزن والتوافر واللون والمزيد.</span> '),(46,1,'Shop Inventory Instructions','    \r\n<div class=\"delivery-term-data-inner\">                    \r\n	<div class=\"heading\">Shop Inventory All the information you need regarding this page</div>                    \r\n	<ul>                        \r\n		<li>This tab contains all the products available to you which can be displayed at the front end store.</li>                        \r\n		<li>For each Product Variant, separate copy needs to be created by Seller either from Master Product tab or clone product icon.</li>                        \r\n		<li>To add new product to your Shop inventory, You have to pick the products from the Master&nbsp; Products tabs by clicking on \"Add Inventory\" button.</li>                    \r\n	</ul>                </div> '),(48,1,'Admin Zones','\r\n<h5>Zones Content File</h5> \r\n<h5>Zone Identifier</h5>\r\n<p>User defined unique identifier for the Zone. This works as a unique key for the system to identify a particular Zone. </p>\r\n<h5>Zone name</h5>\r\n<p>User defined name for the Zone.</p>\r\n<h5>Active</h5>\r\n<p>User defined field to mark a particular zone as active in the system or not. Possible inputs for this field are \'Yes\' &amp; \'No\'. Default value should be set as \'Yes\'.</p>'),(49,1,'Footer meta content','\r\n<div class=\"container\">            \r\n	<div class=\"about-platform\">                \r\n		<h1>Online Shopping Made Easy</h1>                \r\n		<p>If you would like to experience the best of online shopping for men, women and kids in India, you are at the right place. The ultimate destination for fashion and lifestyle, being host to a wide array of merchandise including clothing, footwear, accessories, jewellery, personal care products and more. It is time to redefine your style statement with our treasure-trove of trendy items. This online store brings you the latest in designer products straight out of fashion houses. You can shop online from the comfort of your home and get your favourites delivered right to your doorstep.</p>            </div>            \r\n	<div class=\"about-platform\">                \r\n		<h2>No Cost EMI</h2>                \r\n		<p>In an attempt to make high-end products accessible to all, our No Cost EMI plan enables you to shop with us under EMI, without shelling out any processing fee. Applicable on select mobiles, laptops, large and small appliances, furniture, electronics and watches, you can now shop without burning a hole in your pocket. If you\'ve been eyeing a product for a long time, chances are it may be up for a no cost EMI. Take a look ASAP! Terms and conditions apply.</p>            </div>            \r\n	<div class=\"about-platform\">                \r\n		<h3>Electronic Devices and Accessories</h3>                \r\n		<p>When it comes to laptops, we are not far behind. Filter among dozens of super-fast operating systems, hard disk capacity, RAM, lifestyle, screen size and many other criterias for personalized results in a flash. All you students out there, confused about what laptop to get? Our Back To College Store segregates laptops purpose wise (gaming, browsing and research, project work, entertainment, design, multitasking) with recommendations from top brands and industry experts, facilitating a shopping experience that is quicker and simpler. Photography lovers, you couldn\'t land at a better page than ours. Cutting-edge DSLR cameras, ever reliable point-and-shoot cameras, millennial favourite instant cameras or action cameras for adventure junkies: our range of cameras is as much for beginners as it is for professionals. Canon, Nikon, GoPro, Sony, and Fujifilm are some big names you\'ll find in our store. Photography lovers, you couldn\'t land at a better page than ours. Cutting-edge DSLR cameras, ever reliable point-and-shoot cameras, millennial favourite instant cameras or action cameras for adventure junkies: our range of cameras is as much for beginners as it is for professionals. Canon, Nikon, GoPro, Sony, and Fujifilm are some big names you\'ll find in our store.</p>            </div>        </div>'),(50,1,'Seller Badges Instructions','Badges can be added by admin only.'),(51,1,'Seller Ribbons Instructions','<div class=\"alert alert-info\" role=\"alert\"><div class=\"alert-text\">Ribbons can be added by admin only.</div></div>');
