INSERT INTO `tbl_orders_status` VALUES (1,'Payment Pending',0,1,1,1,0),(2,'Payment Confirmed',0,1,3,1,0),(3,'In Process',0,1,5,1,0),(4,'Shipped',0,1,6,1,0),(5,'Delivered',0,1,7,1,0),(6,'Return Requested',0,1,8,1,0),(7,'Completed',0,1,9,1,0),(8,'Cancelled',0,1,10,1,0),(9,'Refunded/Completed',0,1,11,1,0),(10,'Subscription Inactive',NULL,2,1,1,0),(11,'Subscription Active',NULL,2,2,1,0),(12,'Subscription Cancel',NULL,2,3,1,0),(15,'Approved',0,1,4,1,1),(16,'cash on delivery',0,1,2,1,0),(17,'Pay At Store',NULL,1,2,1,0),(18,'Ready For Pickup',NULL,1,6,1,0);
