INSERT INTO `tbl_plugins_lang` VALUES (1,1,'Fixer Currency Converter API','Reference : https://data.fixer.io'),(1,2,'مثبت العملة API المحولة','Reference : https://data.fixer.io'),(2,1,'Currency Converter API','Reference : https://www.currencyconverterapi.com'),(2,2,'محول العملات API','المرجع: https://www.currencyconverterapi.com'),(3,1,' Sign in with Apple',''),(3,2,' تسجيل الدخول باستخدام Apple',''),(4,1,' Sign in with Facebook',''),(4,2,' تسجيل الدخول باستخدام فيسبوك',''),(5,1,' Sign in with Google',''),(5,2,' تسجيل الدخول باستخدام Google',''),(6,1,' Sign in with Instagram',''),(6,2,' تسجيل الدخول باستخدام Instagram',''),(7,1,'FCM Push Notification',''),(8,1,'Google Shopping Feed','<h6 class=\"mt-2\">Please Follow Below Steps To Get Service Account Detail :</h6>\r\n<ul class=\"listing--bullet\">      \r\n	<li>Visit <a class=\"link\" href=\"https://console.developers.google.com\" target=\"_blank\">Google Console</a></li>            \r\n    <li>Click on <span style=\"font-weight: bold;\">Navigation Menu</span> (Breadcrumb Icon).</li>            \r\n	<li>Open the <span style=\"font-weight: bold;\">IAM &amp; Admin</span> page in the Cloud Console.</li>            \r\n	<li>Click <span style=\"font-weight: bold;\">Select a project</span>, choose a project, and click <span style=\"font-weight: bold;\">Open.</span></li>            \r\n	<li>In the left nav, click <span style=\"font-weight: bold;\">Service accounts.</span></li>            \r\n	<li>Find the row of the service account that you want to create a key for. Follow below steps.</li>\r\n    <li>Steps > In that row, click the <span style=\"font-weight: bold;\">Actions <i class=\"fa fa-ellipsis-v\"></i></span> button, and then click <span style=\"font-weight: bold;\">Create key/Manage Keys.</span></li>\r\n    <li>If service account row not listing on this page. Then click on <span style=\"font-weight: bold;\">Create service account</span> and fill the required information and follow above mentioned steps.</li>           \r\n	<li>Select a <span style=\"font-weight: bold;\">Key type</span> and click <span style=\"font-weight: bold;\">Create.</span> - OR - Select <span style=\"font-weight: bold;\">Add Key</span> and click <span style=\"font-weight: bold;\">Create new key</span> and select <span style=\"font-weight: bold;\">JSON</span> hit Create.</li>\r\n    <li>A JSON file will be downloaded. Open that JSON file copy whole data inside that file and paste it in above <span style=\"font-weight: bold;\">Service account detail</span> input box.</li>\r\n    <li>Hit Save Button</li>\r\n</ul>\r\n<div class=\"divider\"></div>\r\n<h6 class=\"mt-4\">Linking Service Account with Merchant Center Account:</h6>\r\n<ul class=\"listing--bullet\">\r\n    <li>Open that JSON file again and search <span style=\"font-weight: bold;\">client_email</span> and copy its value <span style=\"font-weight: bold;\">XXXX@XXXXXXX.iam.gserviceaccount.com</span>.</li>\r\n    <li>Now visit <a class=\"link\" href=\"https://merchants.google.com/\" target=\"_blank\">Merchant Center</a> and login to your connected Merchant Account.</li>\r\n    <li>Click on the Gear Icon <i class=\"fa fa-cog\"></i> > Account access > Add User > Paste that copied client_email value <span style=\"font-weight: bold;\">XXXX@XXXXXXX.iam.gserviceaccount.com</span> inside.</li>\r\n    <li>Assign Permissions accordingly and save that settings.</li>\r\n</ul>'),(8,2,'جوجل الأعلاف','<h6 class=mt-4>يرجى اتباع الخطوات التالية للحصول علي تفاصيل حساب الخدمة:</h6>        \r\n<ul class=listing--bullet>            \r\n	<li>زيارة <a href=https://console.developers.google.com target=_blank>وحده تحكم Google</a></li>            \r\n	<li>افتح صفحه <span style=font-weight: bold;>المسؤول &Amp; IAM</span> في وحده التحكم بالسحابة.</li>            \r\n	<li>انقر فوق <span style=font-weight: bold;>تحديد مشروع</span>، واختر مشروعا ، ثم انقر فوق <span style=font-weight: bold;>فتح.</span></li>            \r\n	<li>في التنقل الأيمن ، انقر فوق <span style=font-weight: bold;>حسابات الخدمة.</span></li>            \r\n	<li>ابحث عن صف حساب الخدمة الذي تريد إنشاء مفتاح له. في هذا الصف ، انقر فوق زر <span style=font-weight: bold;>المزيد <i class=fa fa-ellipsis-v></i> </span> ثم انقر فوق <span style=font-weight: bold;>إنشاء مفتاح.</span></li>            \r\n	<li>حدد <span style=font-weight: bold;>نوع مفتاح</span> ثم انقر فوق <span style=font-weight: bold;>إنشاء.</span></li>        \r\n</ul>'),(9,1,'PayPal Payout',''),(10,1,'Twilio Sms Notification',''),(11,1,'Avalara Tax','<a href=\"https://developer.avalara.com/api-reference/avatax/rest/v2/\">https://developer.avalara.com/api-reference/avatax/rest/v2/</a>'),(11,2,'ضريبة أفالارا','<a href=\"https://developer.avalara.com/api-reference/avatax/rest/v2/\">https://developer.avalara.com/api-reference/avatax/rest/v2/</a>'),(12,1,'Avalara Tax',''),(13,1,'TaxJar',''),(14,1,'Stripe Connect',''),(15,1,'ShipStation',''),(17,1,'Stripe','\r\n'),(17,2,'Credit Card ','\r\n'),(18,1,'Amazon',''),(20,1,'Braintree',''),(21,1,'Cash On Delivery',''),(22,1,'CCAvenue',''),(23,1,'Citrus',''),(24,1,'EBS',''),(25,1,'Khipu',''),(26,1,'Omise',''),(27,1,'PayFort',''),(28,1,'PayPal',''),(29,1,'Paytm',''),(30,1,'PayU India',''),(31,1,'PayUMoney',''),(32,1,'Razorpay',''),(33,1,'2Checkout',''),(34,1,'Transfer Bank',''),(36,1,'AfterShip Shipment',''),(37,1,'Pay At Store',''),(38,1,'M-Pesa',''),(39,1,'PayGate',''),(40,1,'PayNow',''),(41,1,'Paystack',''),(44,1,'DPO',''),(46,1,'EasyPost',''),(47,1,'Shopify',''),(48,1,'Mollie',''),(49,1,'PayFast',''),(50,1,'QnB',''),(51,1,'Aramex',''),(52,1,'EasyEcom','\n                    <div class=\"cms\">\n                        <div class=\"text-center my-5\">\n                            <small class=\"mb-5\"> FEATURES</small>\n                            <h3> The Complete ERP Solution For Your Business Needs</h3>\n                            <p> Now Sell, Manage, Reconcile all your online and offline businesses from a single\n                                dashboard.</p>\n                        </div>\n                    </div>\n\n                    <ul class=\"list-features\">\n                        <li>\n                            <i class=\"icn fa fa-tv\"></i>\n                            <div class=\"detail cms\">\n                                <h5>Improve Process Fitness</h5>\n                                <p>With more than 50 channels integrated in the panel, our\n                                    omni-channel\n                                    order processing tool helps you increase efficiency.</p>\n                            </div>\n                        </li>\n\n                        <li>\n                            <i class=\"icn  fa fa-wrench\"></i>\n                            <div class=\"detail cms\">\n                                <h5>Smarter Stock Allocation and Purchasing Decision</h5>\n                                <p>Central inventory management system to optimise your overall inventory across\n                                    channels.\n\n                                </p>\n                            </div>\n                        </li>\n                        <li>\n                            <i class=\"icn fa fa-cubes\"></i>\n                            <div class=\"detail cms\">\n                                <h5>Automated Reconciliation Tool\n                                </h5>\n                                <p>Automated reconciliation tool helps you keep a track on returns and unsettled\n                                    invoices.\n\n                                </p>\n                            </div>\n                        </li>\n                        <li>\n                            <i class=\"icn fa fa-code\"></i>\n                            <div class=\"detail cms\">\n                                <h5>Add Efficiency & Quality Control With End to End WMS Solution\n                                </h5>\n                                <p>Our cloud based WMS helps your warehouse team manage multiple warehouses in a\n                                    seamless manner.\n\n                                </p>\n                            </div>\n                        </li>\n                        <li>\n\n                            <i class=\"icn far fa-file-alt\"></i>\n                            <div class=\"detail cms\">\n                                <h5>Eliminate Tedious Data Entry & Duplication\n                                </h5>\n                                <p> Effortless integration of your accounting ERP with EasyEcom reduces error\n                                    and cost involved.\n\n                                </p>\n                            </div>\n                        </li>\n                        <li>\n                            <i class=\"icn fa fa-download\"></i>\n                            <div class=\"detail cms\">\n                                <h5>Gain Competitive Advantage With Data Analysis\n                                </h5>\n                                <p>The in-built advanced data analytics generates reports such as Margin report,\n                                    Sales Report, Inventory forecasting etc helps you grow your business.\n\n                                </p>\n                            </div>\n                        </li>\n                    </ul>'),(53,1,'Yoco',''),(54,1,'Shiprocket',''),(55,1,'ShipEngine','');
/*!40000 ALTER TABLE `tbl_plugins_lang` ENABLE KEYS */;
UNLOCK TABLES;

