INSERT INTO `tbl_sms_templates` VALUES ('account_credited_debited',1,'Transaction Alert','Hello {user_name},\r\nAmount {txn_amount} has been {txn_type} your virtual wallet vide transaction id {txn_id}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{user_name}\"},{\"title\":\"Txn. Amount\", \"variable\":\"{txn_amount}\"},{\"title\":\"Txn. Type\", \"variable\":\"{txn_type}\"},{\"title\":\"Txn Id\", \"variable\":\"{txn_id}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('admin_forgot_password',1,'Forgot Password Admin','Hello {user_full_name},\r\nIt seems that you have used forgot password option at {SITE_NAME}.\r\nPlease click the link to change your password.\r\n{reset_url}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Admin User\", \"variable\":\"{user_full_name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Site Url\", \"variable\":\"{reset_url}\"}]',1),('admin_notification_abusive_review_posted',1,'Product Review Reported','Hello Admin,\r\n{user_full_name} has posted an abusive review at {SITE_NAME}.\r\n{SITE_URL}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Site Url\", \"variable\":\"{SITE_URL}\"}]',1),('admin_order_email',1,'Order Received','Hello Admin,\r\nA new order has been received on your site with Order Invoice Number {order_invoice_number}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Order Invoice Number\", \"variable\":\"{order_invoice_number}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('ADMIN_ORDER_PAYMENT_TRANSFERRED_TO_BANK',1,'Order Payment Transferred To Bank','Hello Admin,\r\n\r\nOrder Payment Detail Submitted BY {USER_NAME}\r\nFor #{ORDER_ID}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{USER_NAME}\"},{\"title\":\"Order Id\", \"variable\":\"{ORDER_ID}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('affiliate_share_invitation_email',1,'Affiliate Invitation','Hello Friend,\r\nThis is an invitation from {user_full_name} to join them on {SITE_NAME} and enjoy Amazing Discounts.\r\nClick the link to accept this invitation:\r\n{tracking_url}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Tracking Url\", \"variable\":\"{tracking_url}\"}]',1),('affiliate_welcome_registration',1,'Affiliate Registration','Hello {name},\r\nThank you for signing up at {SITE_NAME}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('BANK_TRANSFER_ORDER_PAYMENT_ACTIONS',1,'Bank Transfer Order Payment Transaction Action','Dear {USER_NAME},\r\n\r\nPayment txn. of order #{ORDER_ID} has been {STATUS}.\r\nFor #{ORDER_ID}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{USER_NAME}\"},{\"title\":\"Order Id\", \"variable\":\"{ORDER_ID}\"},{\"title\":\"Transaction Status\", \"variable\":\"{STATUS}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('blog_comment_status_changed',1,'Blog Comment Status','Hello {user_full_name},\r\nYour Comment for the blog post \"{post_title}\", posted on {posted_on_datetime} has been {new_status} at {SITE_NAME}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Post Title\", \"variable\":\"{post_title}\"},{\"title\":\"Datetime\", \"variable\":\"{posted_on_datetime}\"},{\"title\":\"New Status\", \"variable\":\"{new_status}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('blog_contribution_status_changed',1,'Blog Contribution Status','Hello {user_full_name},\r\nYour blog contribution posted on {posted_on_datetime} for {SITE_NAME} has been {new_status}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Datetime\", \"variable\":\"{posted_on_datetime}\"},{\"title\":\"New Status\", \"variable\":\"{new_status}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('buyer_notification_review_order_product',1,'Product Review','Hello {user_full_name},\r\nThank you for shopping with {SITE_NAME}. Please share your feedback about your experience.\r\n{SITE_URL}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Site Url\", \"variable\":\"{SITE_URL}\"}]',1),('cancellation_request_approved_declined',1,'Cancellation Request Update','Hello {user_name},\r\nYour order cancellation request for invoice # {invoice_number} has been {request_status} on {SITE_NAME}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{user_name}\"},{\"title\":\"Invoice Number\", \"variable\":\"{invoice_number}\"},{\"title\":\"Request Status\", \"variable\":\"{request_status}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('cancel_subscription_email',1,'Subscription Cancelled','Hello {user_full_name},\r\nYour subscription plan {spackage_name} has been cancelled.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller Shop\", \"variable\":\"{user_full_name}\"},{\"title\":\"Spackage Name\", \"variable\":\"{spackage_name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('child_order_status_change',1,'Order Status Update','Hello {user_full_name},\r\nYour order status for Order ID {invoice_number} has been changed to {new_order_status} at {SITE_NAME}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Invoice Number\", \"variable\":\"{invoice_number}\"},{\"title\":\"New Order Status\", \"variable\":\"{new_order_status}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('COD_OTP_VERIFICATION',1,'COD OTP Verification','Hello {USER_NAME},\r\n{OTP} is the OTP for cash on delivery order verification.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Name\", \"variable\":\"{USER_NAME}\"},{\"title\":\"OTP\", \"variable\":\"{OTP}\"},{\"title\":\"Site Name\", \"variable\":\"{SITE_NAME}\"}]',1),('contact_us',1,'Contact Us','Hello Admin,\r\nA new query has been submitted by {name} on {SITE_NAME}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('COUNTER_RFQ_OFFER_BUYER',1,'Counter RFQ Offer From Buyer','Dear {shop_name} Seller,\r\nCounter offer on {rfq_number} received from {user_name}.\r\nOffer Amount {offer_price} with Quantity {qty} \r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller`s Shop\", \"variable\":\"{shop_name}\"},{\"title\":\"Buyer Name\", \"variable\":\"{user_name}\"},{\"title\":\"Offer Amount\", \"variable\":\"{offer_price}\"}, {\"title\":\"Quantity\", \"variable\":\"{qty}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('COUNTER_RFQ_OFFER_SELLER',1,'Counter RFQ Offer From Seller','Dear {user_name},\r\nCounter offer on {rfq_number} received from {shop_name}.\r\nOffer Amount {offer_price} with Quantity {qty} \r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller`s Shop\", \"variable\":\"{shop_name}\"},{\"title\":\"Buyer Name\", \"variable\":\"{user_name}\"},{\"title\":\"Offer Amount\", \"variable\":\"{offer_price}\"}, {\"title\":\"Quantity\", \"variable\":\"{qty}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('customer_digital_order_email',1,'Cutomer Order Notifiction Digital','Hello {user_full_name},\r\nThank you for placing a digital order on {SITE_NAME}. Your order {order_id} has been received and will be processed.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Order Id\", \"variable\":\"{order_id}\"}]',1),('customer_order_email',1,'Customer Order Notification','Hello {user_full_name},\r\nThank you for placing an order on {SITE_NAME}. Your order {order_invoice_number} has been received and will be processed once payment has been confirmed.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Order Invoice Number\", \"variable\":\"{order_invoice_number}\"}]',1),('data_request_notification_to_admin',1,'Data Request','Hello Admin,\r\nData request has been placed by {user_full_name}\r\nPurpose of request: {ureq_purpose}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Ureq Purpose\", \"variable\":\"{ureq_purpose}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('failed_login_attempt',1,'Failed Login Attempt','Hello {user_full_name},\r\nAre you facing problems logging in at {SITE_NAME}?\r\nUse the forgot password feature to reset your password.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('forgot_password',1,'Forgot Password Users','Hello {user_full_name},\r\nIt seems that you have used forgot password option at {SITE_NAME}.\r\nClick the link to reset your password. Valid for next 24 hours only.\r\n{reset_url}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Site Url\", \"variable\":\"{reset_url}\"}]',1),('gdpr_request_data_to_user',1,'Gdpr Data Request','Hello {username},\r\nYour {request_type} as per our GDPR policy has been received on {SITE_NAME}. Kindly connect with our support team for the next step. \r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{username}\"},{\"title\":\"Request Type\", \"variable\":\"{request_type}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('gdpr_request_status_update_notification_to_user',1,'Gdpr Request','Hello {username},\nYour {request_type} request as per our GDPR policy has been received and completed on {SITE_NAME}. \n\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{username}\"},{\"title\":\"Request Type\", \"variable\":\"{request_type}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('LOGIN',1,'login','Hello {USER_NAME},\r\n{OTP} is the OTP for account verification.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Name\", \"variable\":\"{USER_NAME}\"},{\"title\":\"Otp\", \"variable\":\"{OTP}\"},{\"title\":\"Site Name\", \"variable\":\"{SITE_NAME}\"}]',1),('low_balance_promotional_email',1,'Low Balance Promotions','Hello {user_name},\r\nPlease maintain your wallet balance to keep Promotions Working.\r\nBalance required - {requiredBalance}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{user_name}\"},\r\n{\"title\":\"Balance For promotions Auto debit Required\", \"variable\":\"{requiredBalance}\"}, \r\n{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('low_balance_subscription_email',1,'Low Balance Subscription','Hello {user_full_name},\r\nPlease maintain your wallet balance to Continue Seller Services.\r\nBalance required - {requiredBalance}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Required Balance\", \"variable\":\"{requiredBalance}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('new_affiliate_registration_admin',1,'Affiliate User Sign Up','Hello Admin,\r\nA new affiliate user has registered on {SITE_NAME}.\r\nAffiliate user details:\r\nUsername {username}\r\nEmail {email}\r\nName {name}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Username\", \"variable\":\"{username}\"},{\"title\":\"Email\", \"variable\":\"{email}\"},{\"title\":\"Name\", \"variable\":\"{name}\"}]',1),('new_custom_catalog_request_admin',1,'Custom Catalog Request','Hello Admin,\r\nA new Catalog request by the name of {request_title} is received on {SITE_NAME}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Catalog Name\", \"variable\":\"{request_title}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('new_registration_admin',1,'User Registration','Hello Admin,\r\nA new user has registered on {SITE_NAME}.\r\nUser details:\r\nUsername {username}\r\nEmail {email}\r\nName {name}\r\nType {user_type}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Username\", \"variable\":\"{username}\"},{\"title\":\"Email\", \"variable\":\"{email}\"},{\"title\":\"Name\", \"variable\":\"{name}\"},{\"title\":\"User Type\", \"variable\":\"{user_type}\"}]',1),('NEW_RFQ',1,'Request for New Quotation','Hello Admin,\r\nA new RFQ is received for {rfq_title} ({rfq_number}) with quantity {qty}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"RFQ Title\", \"variable\":\"{rfq_title}\"}, {\"title\":\"Quantity\", \"variable\":\"{qty}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('NEW_RFQ_ASSIGNED',1,'Request for New Quotation Assigned','Hello {shop_user_name},\r\nA new RFQ is assigned for {rfq_title} ({rfq_number}) with quantity {qty}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"RFQ Title\", \"variable\":\"{rfq_title}\"}, {\"title\":\"Quantity\", \"variable\":\"{qty}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('NEW_RFQ_OFFER',1,'New RFQ Offer','Dear {user_name},\r\nA new offer on {rfq_number} received from {shop_name}.\r\nOffer Amount {offer_price} with Quantity {qty} \r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller`s Shop\", \"variable\":\"{shop_name}\"},{\"title\":\"Buyer/Seller Name\", \"variable\":\"{user_name}\"},{\"title\":\"Offer Amount\", \"variable\":\"{offer_price}\"}, {\"title\":\"Quantity\", \"variable\":\"{qty}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('new_seller_approved_admin',1,'New Seller Regisration','Hello Adm