'Subsctiption Auto Renew Notification','Hello {user_full_name},\r\nYour Subscription plan will expire in the next 2 days. Please maintain minimum wallet balance for auto-renew of the plan at {SITE_URL}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller Shop\", \"variable\":\"{user_full_name}\"},{\"title\":\"Web Domain\", \"variable\":\"{SITE_URL}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('subscription_renew_admin',1,'Subscription Renewed','Hello Admin,\r\nSubscription plan has been auto-renewed on {SITE_NAME} with Order Number {invoice_number}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Website\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Invoice Number\", \"variable\":\"{invoice_number}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('subscription_renew_user',1,'Subscription Renewed','Hello {user_full_name},\r\nYour subscription has been renewed vide \r\nOrder Invoice Number {invoice_number} at {SITE_NAME}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller Shop\", \"variable\":\"{user_full_name}\"},{\"title\":\"Invoice Number\", \"variable\":\"{invoice_number}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('supplier_request_status_change_buyer',1,'Seller Approval Request Status','Hello {user_full_name},\r\nYour seller approval request with reference number {reference_number} has been {new_request_status}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Ref Num\", \"variable\":\"{reference_number}\"},{\"title\":\"New Request Status\", \"variable\":\"{new_request_status}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('TEST_SMS_NOTIFICATION',1,'Test Sms Notification','This is the test SMS.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('threshold_notification_vendor',1,'Low Inventory Notification','Hello {user_name},\r\nYour product {prod_title} is low on inventory. Please visit your dashboard to update stock quantity.\r\n{SITE_URL}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{user_name}\"},{\"title\":\"Prod Title\", \"variable\":\"{prod_title}\"},{\"title\":\"Site Url\", \"variable\":\"{SITE_URL}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('user_admin_password_changed_successfully',1,'Password Updated','Hello {user_full_name},\r\nYour password has been changed successfully.\r\nPlease click on the link below to Login to your account.\r\n{SITE_URL}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"Site Url\", \"variable\":\"{SITE_URL}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('user_change_email_request_notification',1,'Email Change Old Email','Hello {user_full_name},\r\nIt seems that you have requested to change email to {new_email} at {SITE_NAME}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"New Email\", \"variable\":\"{new_email}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('user_discount_coupon_notification',1,'Discount Coupon','Hello {user_name},\r\nUse {coupon_code} on your next purchase at{SITE_NAME} to get %{discount_value} off.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Name\", \"variable\":\"{user_name}\"},{\"title\":\"Coupon Code\", \"variable\":\"{coupon_code}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"},{\"title\":\"Discount Value\", \"variable\":\"{discount_value}\"}]',1),('user_email_changed_notification',1,'Email Changed Confirmation','Hello {user_full_name},\r\nYour Email Address has been changed to {new_email} at {SITE_NAME}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"},{\"title\":\"New Email\", \"variable\":\"{new_email}\"},{\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('user_email_verification',1,'Email Verification New Email','Hello {user_full_name},\r\nYou have used change email option at {SITE_NAME}.\r\nYou need to confirm your email to get your account activated with this email address.\r\n{verification_url}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{user_full_name}\"}, {\"title\":\"Verification Url\", \"variable\":\"{verification_url}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('user_send_email',1,'New Email From Admin','Hello {full_name},\r\nYou have a new email from\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User Full Name\", \"variable\":\"{full_name}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('vendor_cod_order_email',1,'Order Received','Hello {vendor_name}\r\nYou have received a new cash on delivery order {order_id} at {SITE_NAME}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller\", \"variable\":\"{vendor_name}\"},{\"title\":\"Order Id\", \"variable\":\"{order_id}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('vendor_digital_order_email',1,'New Digital Order Seller','Hello {vendor_name},\r\nA new order {order_id} is received. Please access the orders tab in you account for more options.\r\n{SITE_URL}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller\", \"variable\":\"{vendor_name}\"},{\"title\":\"Order Id\", \"variable\":\"{order_id}\"},{\"title\":\"Site Url\", \"variable\":\"{SITE_URL}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('vendor_order_email',1,'New Order Seller','Hello {vendor_name},\r\nA new order {order_id} is received. Please access the orders tab in you account for more options.\r\n{SITE_URL}\r\n\r\n{SITE_NAME} Team','[{\"title\":\"Seller\", \"variable\":\"{vendor_name}\"},{\"title\":\"Order Id\", \"variable\":\"{order_id}\"},{\"title\":\"Site Url\", \"variable\":\"{SITE_URL}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('welcome_registration',1,'Welcome Sms Notification','Hello {name},\r\nThank you for signing up at {SITE_URL}.\r\nWe are thrilled to have you aboard! Please access your account for exciting deals & offers.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User\", \"variable\":\"{name}\"},{\"title\":\"Website Domain\", \"variable\":\"{SITE_URL}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('withdrawal_request_admin',1,'Withdrawal Request Received Admin','Hello Admin,\r\n{username} has submitted a withdrawl request {request_id} for {request_amount}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User\", \"variable\":\"{username}\"},{\"title\":\"Request Id\", \"variable\":\"{request_id}\"},{\"title\":\"Amount\", \"variable\":\"{request_amount}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1),('withdrawal_request_approved_declined',1,'Withdrawal Request Status Update','Hello {user_name},\r\nYour fund withdrawal request {request_id} of {request_amount} has been {request_status}.\r\n\r\n{SITE_NAME} Team','[{\"title\":\"User\", \"variable\":\"{user_name}\"},{\"title\":\"Request Id\", \"variable\":\"{request_id}\"},{\"title\":\"Request Amount\", \"variable\":\"{request_amount}\"},{\"title\":\"Request Status\", \"variable\":\"{request_status}\"}, {\"title\":\"Website Name\", \"variable\":\"{SITE_NAME}\"}]',1);
